nStart > len(source) || source[destinationStart-2:destinationStart] != \"](\" {\n+\t\treturn 0, 0, false\n+\t}\n+\tlineStart := strings.LastIndex(source[:destinationStart], \"\\n\") + 1\n+\topenRelative := strings.LastIndex(source[lineStart:destinationStart-2], \"[\")\n+\tif openRelative < 0 {\n+\t\treturn 0, 0, false\n+\t}\n+\tlabelStart := lineStart + openRelative + 1\n+\tlabelEnd := destinationStart - 2\n+\tif source[labelStart:labelEnd] != oldName || !insideManagedFileRegion(source, destinationStart) {\n+\t\treturn 0, 0, false\n+\t}\n+\treturn labelStart, labelEnd, true\n+}\n+\n+func insideManagedFileRegion(source string, offset int) bool {\n+\tfor _, section := range []string{\"files\", \"stubs\"} {\n+\t\tstartMarker := \"<!-- doc-ledger:\" + section + \":start -->\"\n+\t\tendMarker := \"<!-- doc-ledger:\" + section + \":end -->\"\n+\t\tstart := strings.LastIndex(source[:offset], startMarker)\n+\t\tif start < 0 {\n+\t\t\tcontinue\n+\t\t}\n+\t\tendRelative := strings.Index(source[offset:], endMarker)\n+\t\tif endRelative >= 0 {\n+\t\t\treturn true\n+\t\t}\n+\t}\n+\treturn false\n+}\n@@ -0,0 +1,139 @@\n+package links\n+\n+import (\n+\t\"os\"\n+\t\"path/filepath\"\n+\t\"strings\"\n+\t\"testing\"\n+)\n+\n+func TestRepairObservedRenameRewritesInboundLinksFromState(t *testing.T) {\n+\troot := t.TempDir()\n+\toldPath := filepath.Join(root, \"target.md\")\n+\tnewPath := filepath.Join(root, \"renamed.md\")\n+\twriteTestFile(t, oldPath, \"# Target\\n\")\n+\twriteTestFile(t, filepath.Join(root, \"one.md\"), \"[Target](target.md)\\n\")\n+\twriteTestFile(t, filepath.Join(root, \"two.md\"), \"[Target](target.md#section)\\n\")\n+\twriteTestFile(t, filepath.Join(root, \"!INDEX.md\"), \"# Index\\n\\n<!-- doc-ledger:files:start -->\\n- [target.md](target.md) - Target documentation.\\n<!-- doc-ledger:files:end -->\\n\")\n+\tinitializeRenameState(t, root)\n+\tif err := os.Rename(oldPath, newPath); err != nil {\n+\t\tt.Fatal(err)\n+\t}\n+\n+\thandled, changed, err := RepairObserved