ernal/ignore\"\n+\t\"github.com/Lokee86/demon-docs/internal/repository\"\n+\t\"github.com/Lokee86/demon-docs/internal/review\"\n+)\n+\n+// TrackSources refreshes link state for the supplied repository Markdown\n+// sources without rescanning or reparsing the rest of the repository. The\n+// existing file and link manifests are retained for every other source.\n+//\n+// This is intentionally tracking-only: it does not plan generated rewrites,\n+// append review history, or create watcher suppressions.\n+func TrackSources(repositoryRoot string, sourcePaths []string) (Plan, error) {\n+\troot, err := filepath.Abs(repositoryRoot)\n+\tif err != nil {\n+\t\treturn Plan{}, err\n+\t}\n+\troot = filepath.Clean(root)\n+\tpaths, err := scopedSourcePaths(root, sourcePaths)\n+\tif err != nil {\n+\t\treturn Plan{}, err\n+\t}\n+\n+\tfiles, previousLinks, initialized, err := loadState(root)\n+\tif err != nil {\n+\t\treturn Plan{}, err\n+\t}\n+\tif !initialized {\n+\t\treturn Plan{RepositoryRoot: root, NeedsInitialization: true}, nil\n+\t}\n+\tfiles, previousLinks = pruneNestedWorktreeState(root, files, previousLinks)\n+\tpolicy, err := ignorepolicy.Load(root)\n+\tif err != nil {\n+\t\treturn Plan{}, err\n+\t}\n+\tsuppressions, err := LoadPendingSuppressions(root)\n+\tif err != nil {\n+\t\treturn Plan{}, err\n+\t}\n+\n+\tinventory := &inventory{\n+\t\troot:     root,\n+\t\tpolicy:   policy,\n+\t\tmanifest: files,\n+\t}\n+\tinventory.rebuild()\n+\tpreviousBySource := previousLinkIndex(previousLinks)\n+\tselected := map[string]bool{}\n+\tfor _, path := range paths {\n+\t\tstored := storePath(root, path)\n+\t\tif record := inventory.fileByPath(stored); record != nil {\n+\t\t\tselected[record.ID] = true\n+\t\t}\n+\t}\n+\n+\tplan := Plan{\n+\t\tRepositoryRoot:      root,\n+\t\tInitialized:         initialized,\n+\t\tNeedsInitialization: !initialized,\n+\t\tFiles:               inventory.manifest,\n+\t\tLinks:               LinksManifest{SchemaVersion: schemaVersion},\n+\t\tSuppressions:        suppressions,\n+\t}\n+\tfor _, record := range previousLinks.Links {\n+\t\tif !selected[record.SourceFileID] {\n+\t\t\tplan.Links.Links = append(plan.Links.Links, record)\n+\t\t}\n+\t}\n+\n+\tfor _, path := range paths {\n+\t\trecord, err := inventory.refreshScopedFile(path)\n+\t\tif err != nil {\n+\t\t\treturn Plan{}, err\n+\t\t}\n+\t\tif record == nil || record.Kind != \"file\" || !record.Present || !isMarkdown(record.Path) {\n+\t\t\tcontinue\n+\t\t}\n+\t\tpreviousRecords := previousBySource[record.ID]\n+\t\tsource := markdownSource{path: path, record: record}\n+\t\tif err := reconcileMarkdownSource(&plan, inventory, source, previousRecords, initialized, false, review.Policy{}); err != nil {\n+\t\t\treturn Plan{}, err\n+\t\t}\n+\t}\n+\n+\tplan.Files = inventory.manifest\n+\tsortManifests(&plan.Files, &plan.Links)\n+\treturn plan, nil\n+}\n+\n+func scopedSourcePaths(root string, sourcePaths []string) ([]string, error) {\n+\tseen := map[string]bool{}\n+\tpaths := make([]string, 0, len(sourcePaths))\n+\tfor _, sourcePath := range sourcePaths {\n+\t\tpath, err := filepath.Abs(sourcePath)\n+\t\tif err != nil {\n+\t\t\treturn nil, err\n+\t\t}\n+\t\tpath = filepath.Clean(path)\n+\t\tif !repository.Contains(root, path) {\n+\t\t\treturn nil, fmt.Errorf(\"refusing to track source outside repository root: %s\", path)\n+\t\t}\n+\t\tkey := pathKey(path)\n+\t\tif seen[key] {\n+\t\t\tcontinue\n+\t\t}\n+\t\tseen[key] = true\n+\t\tpaths = append(paths, path)\n+\t}\n+\tsort.Slice(paths, func(i, j int) bool { return pathKey(paths[i]) < pathKey(paths[j]) })\n+\treturn paths, nil\n+}\n+\n+func (i *inventory) fileByPath(stored string) *FileRecord {\n+\tfor index := range i.manifest.Files {\n+\t\trecord := &i.manifest.Files[index]\n+\t\tif record.Scope == \"repository\" && pathKey(record.Path) == pathKey(stored) {\n+\t\t\treturn record\n+\t\t}\n+\t}\n+\treturn nil\n+}\n+\n+func (i *inventory) refreshScopedFile(path string) (*FileRecord, error) {\n+\tstored := storePath(i.root, path)\n+\trecord := i.fileByPath(stored)\n+\tinfo, err := os.Stat(path)\n+\tif os.IsNotExist(err) {\n+\t\tif record != nil {\n+\t\t\trecord.Present = false\n+\t\t}\n+\t\treturn record, nil\n+\t}\n+\tif err != nil {\n+\t\treturn nil, fmt.Errorf(\"stat tracked source %s: %w\", path, err)\n+\t}\n+\tif !info.Mode().IsRegular() {\n+\t\treturn nil, nil\n+\t}\n+\tif record == nil {\n+\t\tid, err := newFileID()\n+\t\tif err != nil {\n+\t\t\treturn nil, fmt.Errorf(\"create scoped file identity %s: %w\", stored, err)\n+\t\t}\n+\t\trecord = &FileRecord{ID: id, Scope: \"repository\", Path: stored}\n+\t\ti.manifest.Files = append(i.manifest.Files, *record)\n+\t\ti.rebuild()\n+\t\trecord = i.fileByPath(stored)\n+\t}\n+\trecord.Kind = \"file\"\n+\trecord.Present = true\n+\trecord.Size = info.Size()\n+\trecord.ModifiedUnixNano = info.ModTime().UnixNano()\n+\trecord.Fingerprint, err = fileFingerprint(path)\n+\tif err != nil {\n+\t\treturn nil, fmt.Errorf(\"fingerprint tracked source %s: %w\", path, err)\n+\t}\n+\trecord.DocumentID = \"\"\n+\tif isMarkdown(stored) {\n+\t\trecord.DocumentID = markdownDocumentID(path)\n+\t}\n+\treturn record, nil\n+}\n@@ -0,0 +1,77 @@\n+package links\n+\n+import (\n+\t\"os\"\n+\t\"path/filepath\"\n+\t\"testing\"\n+)\n+\n+func TestTrackSourcesDoesNotInitializeMissingLinkState(t *testing.T) {\n+\troot := t.TempDir()\n+\tsource := filepath.Join(root, \"source.md\")\n+\twriteTestFile(t, source, \"# Source\\n\")\n+\tplan, err := TrackSources(root, []string{source})\n+\tif err != nil {\n+\t\tt.Fatal(err)\n+\t}\n+\tif !plan.NeedsInitialization || plan.Initialized {\n+\t\tt.Fatalf(\"unexpected uninitialized scoped plan: %#v\", plan)\n+\t}\n+\tif _, err := os.Stat(filepath.Join(root, \".ddocs\")); !os.IsNotExist(err) {\n+\t\tt.Fatalf(\"scoped tracking initialized private link state: %v\", err)\n+\t}\n+}\n+\n+func TestTrackSourcesRefreshesOnlySelectedSourceRecords(t *testing.T) {\n+\troot := t.TempDir()\n+\tfirstPath := filepath.Join(root, \"first.md\")\n+\tsecondPath := filepath.Join(root, \"second.md\")\n+\twriteTestFile(t, firstPath, \"# First\\n\\n[Target](target.md)\\n\")\n+\twriteTestFile(t, secondPath, \"# Second\\n\\n[Target](target.md)\\n\")\n+\twriteTestFile(t, filepath.Join(root, \"target.md\"), \"# Target\\n\")\n+\n+\tbaseline, err := Reconcile(root)\n+\tif err != nil {\n+\t\tt.Fatal(err)\n+\t}\n+\tif err := Save(baseline); err != nil {\n+\t\tt.Fatal(err)\n+\t}\n+\tbaseline.Suppressions = []Suppression{{\n+\t\tSourceFileID: baseline.Files.Files[0].ID,\n+\t\tPath:         firstPath,\n+\t}}\n+\tif err := Save(baseline); err != nil {\n+\t\tt.Fatal(err)\n+\t}\n+\tbaselineBySource := linksBySource(baseline.Links.Links)\n+\tif err := os.WriteFile(firstPath, []byte(\"# First\\n\\nAdded context.\\n\\n[Target](target.md)\\n\"), 0o644); err != nil {\n+\t\tt.Fatal(err)\n+\t}\n+\n+\trefresh, err := TrackSources(root, []string{firstPath})\n+\tif err != nil {\n+\t\tt.Fatal(err)\n+\t}\n+\trefreshedBySource := linksBySource(refresh.Links.Links)\n+\tif len(refreshedBySource) != 2 {\n+\t\tt.Fatalf(\"scoped refresh dropped untouched source records: %#v\", refreshedBySource)\n+\t}\n+\tif refreshedBySource[\"first.md\"][0].Start == baselineBySource[\"first.md\"][0].Start {\n+\t\tt.Fatalf(\"selected source link offsets were not refreshed: before=%d after=%d\", baselineBySource[\"first.md\"][0].Start, refreshedBySource[\"first.md\"][0].Start)\n+\t}\n+\tif refreshedBySource[\"second.md\"][0].Start != baselineBySource[\"second.md\"][0].Start {\n+\t\tt.Fatalf(\"untouched source record changed: before=%d after=%d\", baselineBySource[\"second.md\"][0].Start, refreshedBySource[\"second.md\"][0].Start)\n+\t}\n+\tif len(refresh.Suppressions) != 1 || refresh.Suppressions[0].Path != firstPath {\n+\t\tt.Fatalf(\"scoped refresh dropped pending watcher suppression: %#v\", refresh.Suppressions)\n+\t}\n+}\n+\n+func linksBySource(records []LinkRecord) map[string][]LinkRecord {\n+\tresult := map[string][]LinkRecord{}\n+\tfor _, record := range records {\n+\t\tresult[record.SourcePath] = append(result[record.SourcePath], record)\n+\t}\n+\treturn result\n+}\n@@ -3,8 +3,27 @@ package links\n import (\n \t\"os\"\n \t\"path/filepath\"\n+\t\"sort\"\n )\n \n+func mergeSuppressions(existing, generated []Suppression) []Suppression {\n+\tbySource := make(map[string]Suppression, len(existing)+len(generated))\n+\tfor _, suppression := range existing {\n+\t\tbySource[suppression.SourceFileID] = suppression\n+\t}\n+\tfor _, suppression := range generated {\n+\t\tbySource[suppression.SourceFileID] = suppression\n+\t}\n+\tresult := make([]Suppression, 0, len(bySource))\n+\tfor _, suppression := range bySource {\n+\t\tresult = append(result, suppression)\n+\t}\n+\tsort.Slice(result, func(i, j int) bool {\n+\t\treturn result[i].SourceFileID < result[j].SourceFileID\n+\t})\n+\treturn result\n+}\n+\n func ConsumePendingSuppression(repositoryRoot, path string) (bool, error) {\n \tpath = filepath.Clean(path)\n \trecords, err := LoadPendingSuppressions(repositoryRoot)","files":[{"filename":"docs/architecture/application-orchestration.md","patch":"@@ -37,7 +37,7 @@ The application boundary owns:\n - repository and configuration selection;\n - translation of CLI flags into subsystem options;\n - `--docs`, `--frontmatter`, `--format`, `--links`, and `--reverse` selection semantics;\n-- ordering selected reconciliation systems;\n+- ordering selected reconciliation systems, with link repair first, documentation-index writes last, and changed-source link-state refresh scoped to the files written by other systems;\n - command output and aggregate success/failure decisions;\n - orphan-document health-check integration for link-enabled checks;\n - explicit stateless move command integration;"},{"filename":"docs/architecture/reconciliation-command-lifecycle.md","patch":"@@ -252,22 +252,26 @@ The read-only command may load private state. Enabled link checks do not publish\n \n ### Pre-apply planning\n \n-Before the first authored write, `fix` builds only the documentation-index plan when indexes are selected.\n+Before the first authored write, `fix` builds the selected link plan first and the documentation-index plan when indexes are selected.\n \n-Frontmatter and document-format plans are built immediately before their respective applies so they see any earlier index changes. The link plan is built after those writes. The reverse-index plan is deliberately deferred until every earlier selected subsystem has finished, so reverse inventory and rendering observe the final post-policy and post-link repository state.\n+The link plan is built and applied before the other authored-file systems. Frontmatter and document-format plans are built immediately before their respective applies so they see any prepared index content. The reverse-index plan is deliberately deferred until every earlier selected subsystem has finished. The final link-state refresh is not a second repository-wide link pass: when a non-link system changed files, it refreshes only those changed source paths.\n \n ### Mutation order\n \n ```text\n-1. apply documentation-index updates\n-2. build and apply frontmatter updates and immutable state\n-3. build and apply document-format updates and schema history\n-4. reconcile links against the resulting repository contents\n-5. apply generated link rewrites and publish link/review state\n+1. reconcile links against the current repository contents\n+2. apply generated link rewrites and publish link/review state\n+3. prepare documentation-index updates\n+4. build and apply frontmatter updates and immutable state\n+5. build and apply document-format updates and schema history\n 6. build and apply the reverse-index plan\n+7. converge and write documentation indexes last\n+8. refresh link state only for source paths changed by steps 3–7\n ```\n \n-This order gives each later planner the current post-index and post-policy Markdown content. It also keeps reverse-index application last.\n+This order keeps link repair first and documentation-index writes last. The scoped final refresh updates link offsets, fingerprints, and parsed records for files whose content changed after the initial link pass while retaining untouched link state. It performs no generated rewrites, review publication, or watcher-suppression writes.\n+\n+If indexes, frontmatter, format, or reverse-index planning produces no changed file, the final refresh is skipped entirely; in particular, a clean `fix --frontmatter`, `fix --format`, or index-only fix does not perform repository-wide link tracking. Explicit link selection retains the normal full link reconciliation pass and its review, rollback, and suppression behavior.\n \n ### Changed-file count\n "},{"filename":"docs/development/behavioral-contract-matrix.md","patch":"@@ -79,6 +79,7 @@ A test passing does not authorize undocumented contract changes. A document clai\n | Ambiguous targets are reported rather than selected automatically | [Markdown Link Reconciliation](../architecture/markdown-link-reconciliation.md) | `TestAmbiguousGuessIsLeftForTheUser`, wiki ambiguity tests | `ddocs check --links` |\n | Batch preflight prevents every generated source write when any source changed | [Repository State and Transactions](../architecture/repository-state-and-transactions.md) | `TestApplyGeneratedPreflightFailurePreventsAllWrites` | `go test ./internal/links -count=1` |\n | Generated replacement preserves suppression order and deterministic plans | [Watcher and Automation](../operations/watcher-and-automation.md) | `TestApplyGeneratedPreservesSuppressionOrder`, concurrency tests | link integration suite |\n+| Policy and index fixes skip clean-run link tracking and refresh only changed source paths | [Reconciliation Command Lifecycle](../architecture/reconciliation-command-lifecycle.md) | `TestFrontmatterOnlyCleanFixDoesNotRefreshLinkState`, `TestTrackSourcesRefreshesOnlySelectedSourceRecords` | `go test ./internal/app ./internal/links -count=1` |\n | Rollback never overwrites content created after Demon Docs' write | [Repository State and Transactions](../architecture/repository-state-and-transactions.md) | `TestRollbackGeneratedRefusesToOverwriteNewerContent` | full Go suite |\n | Review-publication failure restores generated source content | [Review Ledger](../architecture/review-ledger.md) | `TestApplyAndSaveRestoresSourcesWhenReviewBatchFails`, `TestRollbackAfterReviewFailureRestoresUndoSource` | review CLI integration suite |\n | Stateless move preflights hashes and repository containment | [Stateless Document Refactoring](../guides/document-refactoring.md) | `internal/links/move_test.go`, `internal/app/move_test.go` | `go test ./internal/links ./internal/app -count=1` |"},{"filename":"docs/reference/cli.md","patch":"@@ -88,6 +88,8 @@ Mutation scope: no authored-file writes. Internal read/cache behavior remains im\n \n Computes and applies safe deterministic updates for selected systems, then persists the state needed for later reconciliation.\n \n+Link repair runs first. After frontmatter, document format, reverse indexes, and documentation indexes apply, link state is refreshed only for source paths that changed. A clean frontmatter-only, format-only, or index-only fix does not run repository-wide link tracking. Explicit `--links` retains the full link reconciliation path, including its review history, rollback, and watcher-suppression behavior.\n+\n Mutation scope: managed documentation indexes, configured Markdown frontmatter and body structure beneath the docs root, recognized repository Markdown link paths, configured reverse-index outputs, and private `.ddocs/` state.\n \n ### `ddocs watch`"},{"filename":"internal/app/app.go","patch":"@@ -440,6 +440,7 @@ func runTree(ctx context.Context, command string, args []string, out, errOut io.\n \t}\n \tif command == \"fix\" {\n \t\tchanged := 0\n+\t\tchangedSourcePaths := map[string]bool{}\n \t\tif features.TrackLinks {\n \t\t\tif features.Links {\n \t\t\t\tlin