ryRoot)\n+\t\tif len(changedSourcePaths) > 0 {\n+\t\t\tpaths := sortedChangedSourcePaths(changedSourcePaths)\n+\t\t\tvar refreshPlan links.Plan\n+\t\t\tif features.Links {\n+\t\t\t\t// Link selection keeps its repository-wide refresh so links into\n+\t\t\t\t// newly generated indexes and other selected link diagnostics retain\n+\t\t\t\t// their existing behavior.\n+\t\t\t\trefreshPlan, err = links.Track(scope.RepositoryRoot)\n+\t\t\t} else {\n+\t\t\t\trefreshPlan, err = links.TrackSources(scope.RepositoryRoot, paths)\n+\t\t\t}\n \t\t\tif err != nil {\n \t\t\t\treturn fail(errOut, err)\n \t\t\t}\n-\t\t\tif features.TrackLinks || refreshPlan.Initialized {\n+\t\t\tif refreshPlan.Initialized {\n \t\t\t\tif err := links.Save(refreshPlan); err != nil {\n \t\t\t\t\treturn fail(errOut, err)\n \t\t\t\t}\n@@ -646,6 +661,27 @@ func selectedFeatures(flags commonFlags, c config.Config) watch.Features {\n \t}\n }\n \n+func addChangedSourcePaths(paths map[string]bool, updates []model.FileUpdate) {\n+\tfor _, update := range updates {\n+\t\tpaths[filepath.Clean(update.Path)] = true\n+\t}\n+}\n+\n+func sortedChangedSourcePaths(paths map[string]bool) []string {\n+\tresult := make([]string, 0, len(paths))\n+\tfor path := range paths {\n+\t\tresult = append(result, path)\n+\t}\n+\tsort.Slice(result, func(i, j int) bool {\n+\t\tleft, right := result[i], result[j]\n+\t\tif runtime.GOOS == \"windows\" {\n+\t\t\tleft, right = strings.ToLower(left), strings.ToLower(right)\n+\t\t}\n+\t\treturn left < right\n+\t})\n+\treturn result\n+}\n+\n func writeMessages(out io.Writer, messages []string) {\n \tfor _, message := range messages {\n \t\tfmt.Fprintf(out, \"message: %s\\n\", message)"},{"filename":"internal/app/feature_flags_test.go","patch":"@@ -37,12 +37,69 @@ func TestIndexesAndLinksCanRunSeparately(t *testing.T) {\n \t\tif _, err := os.Stat(filepath.Join(root, \"INDEX.md\")); err != nil {\n \t\t\tt.Fatalf(\"indexes-only run did not create an index: %v\", err)\n \t\t}\n-\t\tif _, err := os.Stat(filepath.Join(root, \".ddocs\", \"objects\")); !os.IsNotExist(err) {\n-\t\t\tt.Fatalf(\"indexes-only run wrote link state: %v\", err)\n+\t\tif _, err := os.Stat(filepath.Join(root, \".ddocs\")); !os.IsNotExist(err) {\n+\t\t\tt.Fatalf(\"indexes-only run initialized link state: %v\", err)\n \t\t}\n \t})\n }\n \n+func TestFrontmatterOnlyCleanFixDoesNotRefreshLinkState(t *testing.T) {\n+\troot := t.TempDir()\n+\tconfigText := strings.Replace(frontmatterTestConfig(false, \"yaml\"), \"[links]\\nenabled = false\", \"[links]\\nenabled = true\", 1)\n+\twriteTestFile(t, filepath.Join(root, \".ddocs\", \"config.toml\"), configText)\n+\tsource := filepath.Join(root, \"docs\", \"source.md\")\n+\twriteTestFile(t, source, \"---\\nauthor: Test Author\\ncreated: 2026-07-20\\ndocument_id: 11111111-2222-4333-8444-555555555555\\ndocument_type: general\\nsummary: Existing\\n---\\n# Source\\n\\n[Target](target.md)\\n\")\n+\twriteTestFile(t, filepath.Join(root, \"docs\", \"target.md\"), \"# Target\\n\")\n+\tvar stdout, stderr bytes.Buffer\n+\tif code := Run(context.Background(), []string{\"fix\", \"--root\", root, \"--links\", \"--no-local-config\", \"--no-global-config\"}, &stdout, &stderr); code != 0 {\n+\t\tt.Fatalf(\"baseline code=%d stdout=%q stderr=%q\", code, stdout.String(), stderr.String())\n+\t}\n+\tbefore := snapshotDirectory(t, filepath.Join(root, \".ddocs\"))\n+\tupdated := \"---\\nauthor: Test Author\\ncreated: 2026-07-20\\ndocument_id: 11111111-2222-4333-8444-555555555555\\ndocument_type: general\\nsummary: Existing\\n---\\n# Source\\n\\n[Target](other.md)\\n\"\n+\twriteTestFile(t, source, updated)\n+\tstdout.Reset()\n+\tstderr.Reset()\n+\tif code := Run(context.Background(), []string{\"fix\", \"--root\", root, \"--frontmatter\", \"--no-local-config\", \"--no-global-config\"}, &stdout, &stderr); code != 0 {\n+\t\tt.Fatalf(\"clean frontmatter code=%d stdout=%q stderr=%q\", code, stdout.String(), stderr.String())\n+\t}\n+\tafter := snapshotDirectory(t, filepath.Join(root, \".ddocs\"))\n+\tif len(before) != len(after) {\n+\t\tt.Fatalf(\"clean frontmatter fix changed link state file count: before=%d after=%d\", len(before), len(after))\n+\t}\n+\tfor path, data := range before {\n+\t\tif string(after[path]) != string(data) {\n+\t\t\tt.Fatalf(\"clean frontmatter fix changed link state %s\", path)\n+\t\t}\n+\t}\n+}\n+\n+func snapshotDirectory(t *testing.T, root string) map[string][]byte {\n+\tt.Helper()\n+\tresult := map[string][]byte{}\n+\terr := filepath.WalkDir(root, func(path string, entry os.DirEntry, err error) error {\n+\t\tif err != nil {\n+\t\t\treturn err\n+\t\t}\n+\t\tif entry.IsDir() {\n+\t\t\treturn nil\n+\t\t}\n+\t\tdata, err := os.ReadFile(path)\n+\t\tif err != nil {\n+\t\t\treturn err\n+\t\t}\n+\t\trelative, err := filepath.Rel(root, path)\n+\t\tif err != nil {\n+\t\t\treturn err\n+\t\t}\n+\t\tresult[relative] = data\n+\t\treturn nil\n+\t})\n+\tif err != nil {\n+\t\tt.Fatal(err)\n+\t}\n+\treturn result\n+}\n+\n func TestReverseSpecificOptionsEnableReverseInDefaultSelection(t *testing.T) {\n \tfeatures := selectedFeatures(commonFlags{reverseRoots: stringsFlag{values: []string{\"services\"}}}, config.Default())\n \tif !features.Indexes || !features.Links || !features.Reverse {"},{"filename":"internal/links/apply.go","patch":"@@ -24,6 +24,10 @@ func applyAndSaveWithTimings(plan *Plan) (int, ApplyTimings, error) {\n }\n \n func applyAndSave(plan *Plan, timings *ApplyTimings) (int, error) {\n+\tpending, err := LoadPendingSuppressions(plan.RepositoryRoot)\n+\tif err != nil {\n+\t\treturn 0, err\n+\t}\n \tchangeBatch, err := prepareGeneratedChanges(plan)\n \tif err != nil {\n \t\treturn 0, err\n@@ -52,7 +56,7 @@ func applyAndSave(plan *Plan, timings *ApplyTimings) (int, error) {\n \t\t}\n \t\treturn 0, err\n \t}\n-\tplan.Suppressions = suppressions\n+\tplan.Suppressions = mergeSuppressions(pending, suppressions)\n \n \tpublicationStarted := time.Now()\n \tif err := Save(*plan); err != nil {"},{"filename":"internal/links/reconcile.go","patch":"@@ -29,7 +29,15 @@ func Reconcile(repositoryRoot string) (Plan, error) {\n // Track refreshes persistent file and link identity without planning user-file\n // rewrites. It is used while automatic link maintenance is disabled.\n func Track(repositoryRoot string) (Plan, error) {\n-\treturn reconcileWithOptions(repositoryRoot, false)\n+\tplan, err := reconcileWithOptions(repositoryRoot, false)\n+\tif err != nil {\n+\t\treturn Plan{}, err\n+\t}\n+\tplan.Suppressions, err = LoadPendingSuppressions(repositoryRoot)\n+\tif err != nil {\n+\t\treturn Plan{}, err\n+\t}\n+\treturn plan, nil\n }\n \n func reconcileWithOptions(repositoryRoot string, repair bool) (Plan, error) {"},{"filename":"internal/links/scoped_tracking.go","patch":"@@ -0,0 +1,169 @@\n+package links\n+\n+import (\n+\t\"fmt\"\n+\t\"os\"\n+\t\"path/filepath\"\n+\t\"sort\"\n+\n+\tignorepolicy \"github.com/Lokee86/demon-docs/internal/ignore\"\n+\t\"github.com/Lokee86/demon-docs/internal/repository\"\n+\t\"github.com/Lokee86/demon-docs/internal/review\"\n+)\n+\n+// TrackSources refreshes link state for the supplied repository Markdown\n+// sources without rescanning or reparsing the rest of the repository. The\n+// existing file and link manifests are retained for every other source.\n+//\n+// This is intentionally tracking-only: it does not plan generated rewrites,\n+// append review history, or create watcher suppressions.\n+func TrackSources(repositoryRoot string, sourcePaths []string) (Plan, error) {\n+\troot, err := filepath.Abs(repositoryRoot)\n+\tif err != nil {\n+\t\treturn Plan{}, err\n+\t}\n+\troot = filepath.Clean(root)\n+\tpaths, err := scopedSourcePaths(root, sourcePaths)\n+\tif err != nil {\n+\t\treturn Plan{}, err\n+\t}\n+\n+\tfiles, previousLinks, initialized, err := loadState(root)\n+\tif err != nil {\n+\t\treturn Plan{}, err\n+\t}\n+\tif !initialized {\n+\t\treturn Plan{RepositoryRoot: root, NeedsInitialization: true}, nil\n+\t}\n+\tfiles, previousLinks = pruneNestedWorktreeState(root, files, previousLinks)\n+\tpolicy, err := ignorepolicy.Load(root)\n+\tif err != nil {\n+\t\treturn Plan{}, err\n+\t}\n+\tsuppressions, err := LoadPendingSuppressions(root)\n+\tif err != nil {\n+\t\treturn Plan{}, err\n+\t}\n+\n+\tinventory := &inventory{\n+\t\troot:     root,\n+\t\tpolicy:   policy,\n+\t\tmanifest: files,\n+\t}\n+\tinventory.rebuild()\n+\tpreviousBySource := previousLinkIndex(previousLinks)\n+\tselected := map[string]bool{}\n+\tfor _, path := range paths {\n+\t\tstored := storePath(root, path)\n+\t\tif record := inventory.fileByPath(stored); record != nil {\n+\t\t\tselected[record.ID] = true\n+\t\t}\n+\t}\n+\n+\tplan := Plan{\n+\t\tRepositoryRoot:      root,\n+\t\tInitialized:         initialized,\n+\t\tNeedsInitialization: !initialized,\n+\t\tFiles:               inventory.manifest,\n+\t\tLinks:               LinksManifest{SchemaVersion: schemaVersion},\n+\t\tSuppressions:        suppressions,\n+\t}\n+\tfor _, record := range previousLinks.Links {\n+\t\tif !selected[record.SourceFileID] {\n+\t\t\tplan.Links.Links = append(plan.Links.Links, record)\n+\t\t}\n+\t}\n+\n+\tfor _, path := range paths {\n+\t\trecord, err := inventory.refreshScopedFile(path)\n+\t\tif err != nil {\n+\t\t\treturn Plan{}, err\n+\t\t}\n+\t\tif record == nil || record.Kind != \"file\" || !record.Present || !isMarkdown(record.Path) {\n+\t\t\tcontinue\n+\t\t}\n+\t\tpreviousRecords := previousBySource[record.ID]\n+\t\tsource := markdownSource{path: path, record: record}\n+\t\tif err := reconcileMarkdownSource(&plan, inventory, source, previousRecords, initialized, false, review.Policy{}); err != nil {\n+\t\t\treturn Plan{}, err\n+\t\t}\n+\t}\n+\n+\tplan.Files = inventory.manifest\n+\tsortManifests(&plan.Files, &plan.Links)\n+\treturn plan, nil\n+}\n+\n+func scopedSourcePaths(root string, sourcePaths []string) ([]string, error) {\n+\tseen := map[string]bool{}\n+\tpaths := make([]string, 0, len(sourcePaths))\n+\tfor _, sourcePath := range sourcePaths {\n+\t\tpath, err := filepath.Abs(sourcePath)\n+\t\tif err != nil {\n+\t\t\treturn nil, err\n+\t\t}\n+\t\tpath = filepath.Clean(path)\n+\t\tif !repository.Contains(root, path) {\n+\t\t\treturn nil, fmt.Errorf(\"refusing to track source outside repository root: %s\", path)\n+\t\t}\n+\t\tkey := pathKey(path)\n+\t\tif seen[key] {\n+\t\t\tcontinue\n+\t\t}\n+\t\tseen[key] = true\n+\t\tpaths = append(paths, path)\n+\t}\n+\tsort.Slice(paths, func(i, j int) bool { return pathKey(paths[i]) < pathKey(paths[j]) })\n+\treturn paths, nil\n+}\n+\n+func (i *inventory) fileByPath(stored string) *FileRecord {\n+\tfor index := range i.manifest.Files {\n+\t\trecord := &i.manifest.Files[index]\n+\t\tif record.Scope == \"repository\" && pathKey(record.Path) == pathKey(stored) {\n+\t\t\treturn record\n+\t\t}\n+\t}\n+\treturn nil\n+}\n+\n+func (i *inventory) refreshScopedFile(path string) (*FileRecord, error) {\n+\tstored := storePath(i.root, path)\n+\trecord := i.fileByPath(stored)\n+\tinfo, err := os.Stat(path)\n+\tif os.IsNotExist(err) {\n+\t\tif record != nil {\n+\t\t\trecord.Present = false\n+\t\t}\n+\t\treturn record, nil\n+\t}\n+\tif err != nil {\n+\t\treturn nil, fmt.Errorf(\"stat tracked source %s: %w\", path, err)\n+\t}\n+\tif !info.Mode().IsRegular() {\n+\t\treturn nil, nil\n+\t}\n+\tif record == nil {\n+\t\tid, err := newFileID()\n+\t\tif err != nil {\n+\t\t\treturn nil, fmt.Errorf(\"create scoped file identity %s: %w\", stored, err)\n+\t\t}\n+\t\trecord = &FileRecord{ID: id, Scope: \"repository\", Path: stored}\n+\t\ti.manifest.Files = append(i.manifest.Files, *record)\n+\t\ti.rebuild()\n+\t\trecord = i.fileByPath(stored)\n+\t}\n+\trecord.Kind = \"file\"\n+\trecord.Present = true\n+\trecord.Size = info.Size()\n+\trecord.ModifiedUnixNano = info.ModTime().UnixNano()\n+\trecord.Fingerprint, err = fileFingerprint(path)\n+\tif err != nil {\n+\t\treturn nil, fmt.Errorf(\"fingerprint tracked source %s: %w\", path, err)\n+\t}\n+\trecord.DocumentID = \"\"\n+\tif isMarkdown(stored) {\n+\t\trecord.DocumentID = markdownDocumentID(path)\n+\t}\n+\treturn record, nil\n+}"},{"filename":"internal/links/scoped_tracking_test.go","patch":"@@ -0,0 +1,77 @@\n+package links\n+\n+import (\n+\t\"os\"\n+\t\"path/filepath\"\n+\t\"testing\"\n+)\n+\n+func TestTrackSourcesDoesNotInitializeMissingLinkState(t *testing.T) {\n+\troot := t.TempDir()\n+\tsource := filepath.Join(root, \"source.md\")\n+\twriteTestFile(t, source, \"# Source\\n\")\n+\tplan, err := TrackSources(root, []string{source})\n+\tif err != nil {\n+\t\tt.Fatal(err)\n+\t}\n+\tif !plan.NeedsInitialization || plan.Initialized {\n+\t\tt.Fatalf(\"unexpected uninitialized scoped plan: %#v\", plan)\n+\t}\n+\tif _, err := os.Stat(filepath.Join(root, \".ddocs\")); !os.IsNotExist(err) {\n+\t\tt.Fatalf(\"scoped tracking initialized private link state: %v\", err)\n+\t}\n+}\n+\n+func TestTrackSourcesRefreshesOnlySelectedSourceRecords(t *testing.T) {\n+\troot := t.TempDir()\n+\tfirstPath := filepath.Join(root, \"first.md\")\n+\tsecondPath := filepath.Join(root, \"second.md\")\n+\twriteTestFile(t, firstPath, \"# First\\n\\n[Target](target.md)\\n\")\n+\twriteTestFile(t, secondPath, \"# Second\\n\\n[Target](target.md)\\n\")\n+\twriteTestFile(t, filepath.Join(root, \"target.md\"), \"# Target\\n\")\n+\n+\tbaseline, err := Reconcile(root)\n+\tif err != nil {\n+\t\tt.Fatal(err)\n+\t}\n+\tif err := Save(baseline); err != nil {\n+\t\tt.Fatal(err)\n+\t}\n+\tbaseline.Suppressions = []Suppression{{\n+\t\tSourceFileID: baseline.Files.Files[0].ID,\n+\t\tPath:         firstPath,\n+\t}}\n+\tif err := Save(baseline); err != nil {\n+\t\tt.Fatal(err)\n+\t}\n+\tbaselineBySource := linksBySource(baseline.Links.Links)\n+\tif err := os.WriteFile(firstPath, []byte(\"# First\\n\\nAdded context.\\n\\n[Target](target.md)\\n\"), 0o644); err != nil {\n+\t\tt.Fatal(err)\n+\t}\n+\n+\trefresh, err := TrackSources(root, []string{firstPath})\n+\tif err != nil {\n+\t\tt.Fatal(err)\n+\t}\n+\trefreshedBySource := linksBySource(refresh.Links.Links)\n+\tif len(refreshedBySource) != 2 {\n+\t\tt.Fatalf(\"scoped refresh dropped untouched source records: %#v\", refreshedBySource)\n+\t}\n+\tif refreshedBySource[\"first.md\"][0].Start == baselineBySource[\"first.md\"][0].Start {\n+\t\tt.Fatalf(\"selected source link offsets were not refreshed: before=%d after=%d\", baselineBySource[\"first.md\"][0].Start, refreshedBySource[\"first.md\"][0].Start)\n+\t}\n+\tif refreshedBySource[\"second.md\"][0].Start != baselineBySource[\"second.md\"][0].Start {\n+\t\tt.Fatalf(\"untouched source record changed: before=%d after=%d\", baselineBySource[\"second.md\"][0].Start, refreshedBySource[\"second.md\"][0].Start)\n+\t}\n+\tif len(refresh.Suppressions) != 1 || refresh.Suppressions[0].Path != firstPath {\n+\t\tt.Fatalf(\"scoped refresh dropped pending watcher suppression: %#v\", refresh.Suppressions)\n+\t}\n+}\n+\n+func linksBySource(records []LinkRecord) map[string][]LinkRecord {\n+\tresult := map[string][]LinkRecord{}\n+\tfor _, record := range records {\n+\t\tresult[record.SourcePath] = append(result[record.SourcePath], record)\n+\t}\n+\treturn result\n+}"},{"filename":"internal/links/suppression.go","patch":"@@ -3,8 +3,27 @@ package links\n import (\n \t\"os\"\n \t\"path/filepath\"\n+\t\"sort\"\n )\n \n+func mergeSuppressions(existing, generated []Suppression) []Suppression {\n+\tbySource := make(map[string]Suppression, len(existing)+len(generated))\n+\tfor _, suppression := range existing {\n+\t\tbySource[suppression.SourceFileID] = suppression\n+\t}\n+\tfor _, suppression := range generated {\n+\t\tbySource[suppression.SourceFileID] = suppression\n+\t}\n+\tresult := make([]Suppression, 0, len(bySource))\n+\tfor _, suppression := range bySource {\n+\t\tresult = append(result, suppression)\n+\t}\n+\tsort.Slice(result, func(i, j int) bool {\n+\t\treturn result[i].SourceFileID < result[j].SourceFileID\n+\t})\n+\treturn result\n+}\n+\n func ConsumePendingSuppression(repositoryRoot, path string) (bool, error) {\n \tpath = filepath.Clean(path)\n \trecords, err :=