rk is `BenchmarkInitialIndexing`. Run both with:\n+\n+```bash\n+go test ./internal/links -run '^$' -bench '^(BenchmarkInitialIndexing|BenchmarkSingleFileIncrementalUpdate)$' -benchmem -count=5\n+```\n+\n ## Research status\n \n Recorded benchmark evidence. New performance changes should preserve the original artifacts and add comparable runs rather than overwriting historical results.\n@@ -15,6 +15,10 @@ func markdownDocumentID(path string) string {\n \tif err != nil {\n \t\treturn \"\"\n \t}\n+\treturn markdownDocumentIDBytes(data)\n+}\n+\n+func markdownDocumentIDBytes(data []byte) string {\n \tdocument, err := frontmatter.Parse(string(data), []string{frontmatter.FormatYAML, frontmatter.FormatTOML})\n \tif err != nil || !document.HasBlock {\n \t\treturn \"\"\n@@ -25,6 +25,11 @@ func fileFingerprint(path string) (string, error) {\n \treturn \"sha256:\" + hex.EncodeToString(hash.Sum(nil)), nil\n }\n \n+func bytesFingerprint(data []byte) string {\n+\tdigest := sha256.Sum256(data)\n+\treturn \"sha256:\" + hex.EncodeToString(digest[:])\n+}\n+\n func recordAbsolute(root string, record FileRecord) string {\n \tif record.Scope == \"repository\" {\n \t\treturn filepath.Clean(filepath.Join(root, filepath.FromSlash(record.Path)))\n@@ -16,6 +16,23 @@ type inventoryNode struct {\n \tsize, modified                             int64\n }\n \n+type inventoryContentJob struct {\n+\tpath     string\n+\tmarkdown bool\n+}\n+\n+func readInventoryContent(job inventoryContentJob) (string, string, error) {\n+\tif !job.markdown {\n+\t\tfingerprint, err := fileFingerprint(job.path)\n+\t\treturn fingerprint, \"\", err\n+\t}\n+\tdata, err := os.ReadFile(job.path)\n+\tif err != nil {\n+\t\treturn \"\", \"\", err\n+\t}\n+\treturn bytesFingerprint(data), markdownDocumentIDBytes(data), nil\n+}\n+\n type inventory struct {\n \troot     string\n \tpolicy   ignorepolicy.Policy\n@@ -38,6 +55,7 @@ func buildInventory(root string, previous FilesManifest) (*inventory, error) {\n \t}\n \tvar nodes []inven