t-body format only\\n  -l, --links           repository-local Markdown links and orphan health\\n  -r, --reverse         code-folder reverse indexes\\n  -i, --indexes         documentation indexes only\\n\\nUse selectors with check, fix, or watch.\\n\\noptions:\\n  -h, --help            show this help message and exit\\n  -v, --version         show program's version number and exit\\n\\nExamples:\\n  ddocs init --root docs\\n  ddocs schema init\\n  ddocs new service docs/services/new-service.md\\n  ddocs check --frontmatter\\n  ddocs fix --format\\n  ddocs format ignore --heading Appendix docs/guide.md\\n  ddocs codemaps fix --root docs/architecture --dry-run\\n  ddocs codemaps export\\n  ddocs fix\\n  ddocs check -r\\n  ddocs mv --dry-run docs/old.md docs/new.md\\n  ddocs check --help\\n  ddocs demon --help\\n  ddocs config paths\\n  ddocs --version\\n\", topUsageLine)\n }\n \n func initHelp(w io.Writer) {\n@@ -286,7 +286,7 @@ func writeInitParseError(w io.Writer, err error) {\n }\n \n func treeUsage(command string) string {\n-\tusage := fmt.Sprintf(\"usage: ddocs %s [-h] [-d] [--frontmatter] [--format] [-l] [-r] [--root PATH] [--config PATH]\\n\", command) +\n+\tusage := fmt.Sprintf(\"usage: ddocs %s [-h] [-d] [-i] [--frontmatter] [--format] [-l] [-r] [--root PATH] [--config PATH]\\n\", command) +\n \t\t\"                     [--no-local-config] [--no-global-config] [--index-file NAME]\\n\" +\n \t\t\"                     [--reverse-root PATH] [--codemap-heading TEXT]\\n\" +\n \t\t\"                     [--draft-folder NAME] [--draft-description-prefix TEXT]\\n\" +\n@@ -313,7 +313,7 @@ func treeHelp(w io.Writer, command string) {\n \t\twatchOptions = \"  --once                run one reconciliation pass and exit\\n  --debounce-seconds FLOAT\\n                        override the watcher debounce interval\\n\"\n \t\twatchNotes = \"\\nWatcher lifecycle:\\n  - ddocs watch remains attached to the current terminal\\n  - use ddocs demon for detached, repository-local sel