dates\\n    check               verify selected systems without writing\\n    watch               reconcile selected systems and watch for changes\\n    codemaps            generate, check, inspect, export, and benchmark codemaps\\n    suggestions         inspect and decide unresolved repair suggestions\\n    changes             inspect, undo, and block applied repairs\\n    config              inspect config path selection and resolved config\\n    index               enable or disable repository index management\\n    links               enable or disable automatic link maintenance\\n    demon               manage the repository-local self-managing watcher\\n\\nreconciliation selectors:\\n  -d, --docs            indexes, frontmatter, and document-body format\\n  --frontmatter         configured frontmatter only\\n  --format              document-body format only\\n  -l, --links           repository-local Markdown links and orphan health\\n  -r, --reverse         code-folder reverse indexes\\n  -i, --indexes         documentation indexes only\\n\\nUse selectors with check, fix, or watch.\\n\\noptions:\\n  -h, --help            show this help message and exit\\n  -v, --version         show program's version number and exit\\n\\nExamples:\\n  ddocs init --root docs\\n  ddocs schema init\\n  ddocs new service docs/services/new-service.md\\n  ddocs check --frontmatter\\n  ddocs fix --format\\n  ddocs format ignore --heading Appendix docs/guide.md\\n  ddocs codemaps fix --root docs/architecture --dry-run\\n  ddocs codemaps export\\n  ddocs fix\\n  ddocs check -r\\n  ddocs mv --dry-run docs/old.md docs/new.md\\n  ddocs check --help\\n  ddocs demon --help\\n  ddocs config paths\\n  ddocs --version\\n\", topUsageLine)\n }\n \n func initHelp(w io.Writer) {\n@@ -286,7 +286,7 @@ func writeInitParseError(w io.Writer, err error) {\n }\n \n func treeUsage(command string) string {\n-\tusage := fmt.Sprintf(\"usage: ddocs %s [-h] [-d] [--frontmatter] [--format] [-l] [-r] [--root PA