"} {\n+\t\tif err := os.WriteFile(filepath.Join(docs, name), []byte(text), 0o644); err != nil {\n+\t\t\tt.Fatal(err)\n+\t\t}\n+\t}\n+\tcfg := config.Default()\n+\tcfg.Root = \"docs\"\n+\tcfg.Frontmatter = schema()\n+\tfirstPath := filepath.Join(docs, \"b.md\")\n+\tif err := os.Remove(firstPath); err != nil {\n+\t\tt.Fatal(err)\n+\t}\n+\tif _, err := Build(root, docs, cfg, false, time.Now()); err != nil {\n+\t\tt.Fatal(err)\n+\t}\n+\tif err := os.WriteFile(firstPath, []byte(text), 0o644); err != nil {\n+\t\tt.Fatal(err)\n+\t}\n+\tplan, err := Build(root, docs, cfg, false, time.Now())\n+\tif err != nil {\n+\t\tt.Fatal(err)\n+\t}\n+\tif plan.cacheHits != 0 || len(plan.Diagnostics) != 2 || !hasUnresolved(plan.Diagnostics, \"document_id\") {\n+\t\tt.Fatalf(\"duplicate ID was hidden by cache: hits=%d diagnostics=%v\", plan.cacheHits, plan.Diagnostics)\n+\t}\n+}\n+\n+func TestFixPublishesImmutableValuesRetainedByCheckCache(t *testing.T) {\n+\troot := t.TempDir()\n+\tdocs := filepath.Join(root, \"docs\")\n+\tif err := os.MkdirAll(docs, 0o755); err != nil {\n+\t\tt.Fatal(err)\n+\t}\n+\tif _, err := ddrepo.Init(root); err != nil {\n+\t\tt.Fatal(err)\n+\t}\n+\tpath := filepath.Join(docs, \"guide.md\")\n+\ttext := \"---\\nauthor: Human\\ncreated: '2026-07-20'\\ndocument_id: 11111111-2222-4333-8444-555555555555\\ndocument_type: guide\\nsummary: Existing\\n---\\n# Guide\\n\"\n+\tif err := os.WriteFile(path, []byte(text), 0o644); err != nil {\n+\t\tt.Fatal(err)\n+\t}\n+\tcfg := config.Default()\n+\tcfg.Root = \"docs\"\n+\tcfg.Frontmatter = schema()\n+\tnow := time.Date(2026, 7, 20, 0, 0, 0, 0, time.UTC)\n+\tif _, err := Build(root, docs, cfg, false, now); err != nil {\n+\t\tt.Fatal(err)\n+\t}\n+\tplan, err := Build(root, docs, cfg, true, now)\n+\tif err != nil {\n+\t\tt.Fatal(err)\n+\t}\n+\tif plan.cacheHits != 1 || len(plan.immutable) != 1 {\n+\t\tt.Fatalf(\"fix did not recover immutable values from cache: hits=%d immutable=%v\", plan.cacheHits, plan.immutable)\n+\t}\n+\tif _, err := Apply(root, docs, plan); err != nil {\n+\t\tt.Fatal(err)\n+\t}\n+\tfinal, err := Build(root, docs, cfg, false, now)\n+\tif err != nil {\n+\t\tt.Fatal(err)\n+\t}\n+\tif final.cacheHits != 1 || final.Failed() {\n+\t\tt.Fatalf(\"immutable publication changed clean cache result: hits=%d diagnostics=%v\", final.cacheHits, final.Diagnostics)\n+\t}\n+}\n@@ -34,6 +34,10 @@ func Read(path string) (Document, error) {\n \treturn Decode(b), nil\n }\n \n+// RawBytes returns the original file bytes used for content identity. The\n+// normalized Text field remains the source-preserving editing representation.\n+func (d Document) RawBytes() []byte { return []byte(d.raw) }\n+\n func (d Document) Encode(text string) []byte {\n \tif d.mixed {\n \t\treturn []byte(d.encodeMixed(text))\n@@ -0,0 +1,276 @@\n+package validationcache\n+\n+import (\n+\t\"crypto/sha256\"\n+\t\"encoding/hex\"\n+\t\"encoding/json\"\n+\t\"errors\"\n+\t\"os\"\n+\t\"path/filepath\"\n+\t\"runtime\"\n+\t\"sort\"\n+\t\"strings\"\n+\n+\t\"github.com/Lokee86/demon-docs/internal/config\"\n+\t\"github.com/Lokee86/demon-docs/internal/ddrepo\"\n+)\n+\n+const (\n+\tEngineVersion = \"validation-engine-v1\"\n+\tprefix        = \"validation-cache/\"\n+\tschemaVersion = 1\n+)\n+\n+// Entry is the durable identity and clean-result state for one document.\n+// The two clean flags are merged by frontmatter and document-policy builders.\n+type Entry struct {\n+\tSchemaVersion         int            `json:\"schema_version\"`\n+\tPath                  string         `json:\"path\"`\n+\tContentSHA256         string         `json:\"content_sha256\"`\n+\tEngineVersion         string         `json:\"engine_version\"`\n+\tFrontmatterPolicyHash string         `json:\"frontmatter_policy_hash\"`\n+\tEffectiveSchemaHash   string         `json:\"effective_schema_hash\"`\n+\tImmutableSnapshotHash string         `json:\"immutable_snapshot_hash\"`\n+\tDocumentID            string         `json:\"document_id,omitempty\"`\n+\tDocumentType          string         `json:\"document_type,omitempty\"`\n+\tSchemaName            string         `json:\"schema_name,omitempty\"`\n+\tImmutableValues       map[string]any `json:\"immutable_values,omitempty\"`\n+\tFrontmatterClean      bool           `json:\"frontmatter_clean\"`\n+\tFormatClean           bool           `json:\"format_clean\"`\n+}\n+\n+type Store struct {\n+\trepository *ddrepo.Repository\n+\tentries    map[string]Entry\n+\tdirty      map[string]Entry\n+\tdeleted    map[string]bool\n+}\n+\n+func Open(repoRoot string) (*Store, error) {\n+\tstore := &Store{entries: map[string]Entry{}, dirty: map[string]Entry{}, deleted: map[string]bool{}}\n+\tprivateState := filepath.Join(repoRoot, \".ddocs\")\n+\trepository, err := ddrepo.Open(privateState)\n+\tif err != nil {\n+\t\tif _, statErr := os.Stat(privateState); errors.Is(statErr, os.ErrNotExist) || missingPrivateState(repoRoot) {\n+\t\t\treturn store, nil\n+\t\t}\n+\t\treturn nil, err\n+\t}\n+\tstore.repository = repository\n+\ttx, err := repository.Begin()\n+\tif err != nil {\n+\t\treturn nil, err\n+\t}\n+\tnames, err := tx.Names(prefix)\n+\tif err != nil {\n+\t\treturn nil, err\n+\t}\n+\tfor _, name := range names {\n+\t\tdata, err := tx.Read(name)\n+\t\tif err != nil {\n+\t\t\treturn nil, err\n+\t\t}\n+\t\tvar entry Entry\n+\t\tif json.Unmarshal(data, &entry) != nil || entry.SchemaVersion != schemaVersion || entry.Path == \"\" {\n+\t\t\tcontinue\n+\t\t}\n+\t\tstore.entries[entry.Path] = entry\n+\t}\n+\treturn store, nil\n+}\n+\n+func (s *Store) Lookup(path, contentHash, frontmatterPolicyHash, schemaHash, immutableHash string) (Entry, bool) {\n+\tif s == nil {\n+\t\treturn Entry{}, false\n+\t}\n+\tentry, ok := s.entries[NormalizePath(path)]\n+\tif !ok || entry.SchemaVersion != schemaVersion || entry.Path != NormalizePath(path) ||\n+\t\tentry.ContentSHA256 != contentHash || entry.EngineVersion != EngineVersion ||\n+\t\tentry.FrontmatterPolicyHash != frontmatterPolicyHash || entry.EffectiveSchemaHash != schemaHash ||\n+\t\tentry.ImmutableSnapshotHash != immutableHash {\n+\t\treturn Entry{}, false\n+\t}\n+\treturn entry, true\n+}\n+\n+// Candidate returns a path/content/version/policy match before the caller has\n+// re-read the selected schema. It is used to recover the selection metadata\n+// needed to compute the current effective schema hash without parsing Markdown.\n+func (s *Store) Candidate(path, contentHash, frontmatterPolicyHash string) (Entry, bool) {\n+\tif s == nil {\n+\t\treturn Entry{}, false\n+\t}\n+\tentry, ok := s.entries[NormalizePath(path)]\n+\tif !ok || entry.SchemaVersion != schemaVersion || entry.Path != NormalizePath(path) ||\n+\t\tentry.ContentSHA256 != contentHash || entry.EngineVersion != EngineVersion ||\n+\t\tentry.FrontmatterPolicyHash != frontmatterPolicyHash {\n+\t\treturn Entry{}, false\n+\t}\n+\treturn entry, true\n+}\n+\n+func (s *Store) Merge(entry Entry) {\n+\tif s == nil || !entry.FrontmatterClean && !entry.FormatClean {\n+\t\treturn\n+\t}\n+\tentry.SchemaVersion = schemaVersion\n+\tentry.Path = NormalizePath(entry.Path)\n+\tif previous, ok := s.entries[entry.Path]; ok && sameIdentity(previous, entry) {\n+\t\tentry.FrontmatterClean = entry.FrontmatterClean || previous.FrontmatterClean\n+\t\tentry.FormatClean = entry.FormatClean || previous.FormatClean\n+\t\tif entry.DocumentID == \"\" {\n+\t\t\tentry.DocumentID = previous.DocumentID\n+\t\t}\n+\t\tif entry.DocumentType == \"\" {\n+\t\t\tentry.DocumentType = previous.DocumentType\n+\t\t}\n+\t\tif entry.SchemaName == \"\" {\n+\t\t\tentry.SchemaName = previous.SchemaName\n+\t\t}\n+\t\tif entry.ImmutableValues == nil {\n+\t\t\tentry.ImmutableValues = previous.ImmutableValues\n+\t\t}\n+\t}\n+\ts.entries[entry.Path] = entry\n+\ts.dirty[entry.Path] = entry\n+}\n+\n+// Retain drops cache records for documents that are no longer in the active\n+// validation scope. Deletion is published with the next Save call.\n+func (s *Store) Retain(paths []string) {\n+\tif s == nil {\n+\t\treturn\n+\t}\n+\tactive := make(map[string]bool, len(paths))\n+\tfor _, path := range paths {\n+\t\tactive[NormalizePath(path)] = true\n+\t}\n+\tfor path := range s.entries {\n+\t\tif active[path] {\n+\t\t\tcontinue\n+\t\t}\n+\t\tdelete(s.entries, path)\n+\t\tdelete(s.dirty, path)\n+\t\ts.deleted[path] = true\n+\t}\n+}\n+\n+func (s *Store) Save() error {\n+\tif s == nil || s.repository == nil || len(s.dirty) == 0 && len(s.deleted) == 0 {\n+\t\treturn nil\n+\t}\n+\tdeleted := make([]string, 0, len(s.deleted))\n+\tfor path := range s.deleted {\n+\t\tdeleted = append(deleted, path)\n+\t}\n+\tpaths := make([]string, 0, len(s.dirty))\n+\tfor path := range s.dirty {\n+\t\tpaths = append(paths, path)\n+\t}\n+\tsort.Strings(deleted)\n+\tsort.Strings(paths)\n+\tif err := s.repository.Transaction(func(tx *ddrepo.Transaction) error {\n+\t\tfor _, path := range deleted {\n+\t\t\tif err := tx.Delete(recordName(path)); err != nil {\n+\t\t\t\treturn err\n+\t\t\t}\n+\t\t}\n+\t\tfor _, path := range paths {\n+\t\t\tdata, err := json.Marshal(s.dirty[path])\n+\t\t\tif err != nil {\n+\t\t\t\treturn err\n+\t\t\t}\n+\t\t\tif err := tx.Write(recordName(path), data); err != nil {\n+\t\t\t\treturn err\n+\t\t\t}\n+\t\t}\n+\t\treturn nil\n+\t}); err != nil {\n+\t\treturn err\n+\t}\n+\ts.dirty = map[string]Entry{}\n+\ts.deleted = map[string]bool{}\n+\treturn nil\n+}\n+\n+func Hash(value any) string {\n+\tdata, err := json.Marshal(value)\n+\tif err != nil {\n+\t\treturn \"\"\n+\t}\n+\tdigest := sha256.Sum256(data)\n+\treturn hex.EncodeToString(digest[:])\n+}\n+\n+// FrontmatterPolicyHash covers frontmatter rules and the format-selection and\n+// index defaults that can change the effective frontmatter schema.\n+func FrontmatterPolicyHash(cfg config.Config) string {\n+\treturn Hash(struct {\n+\t\tFrontmatter config.Frontmatter\n+\t\tIndexFile   string\n+\t\tFormat      config.Format\n+\t}{cfg.Frontmatter, cfg.IndexFile, cfg.Format})\n+}\n+\n+func ContentHash(data []byte) string {\n+\tdigest := sha256.Sum256(data)\n+\treturn hex.EncodeToString(digest[:])\n+}\n+\n+func NormalizePath(path string) string {\n+\tpath = filepath.ToSlash(filepath.Clean(path))\n+\tif runtime.GOOS == \"windows\" {\n+\t\tpath = strings.ToLower(path)\n+\t}\n+\treturn path\n+}\n+\n+// EffectiveSchemaHash fingerprints the selected shared and document-specific\n+// schema sources. Missing shared sources are built-in engine inputs and are\n+// invalidated by EngineVersion; missing local sources are explicit selections.\n+func EffectiveSchemaHash(repoRoot string, format config.Format, schemaName, documentID string) string {\n+\tif !format.Enabled || strings.TrimSpace(schemaName) == \"\" {\n+\t\treturn Hash(\"format-disabled\")\n+\t}\n+\tsharedPath := resolveSchemaPath(repoRoot, format.SchemaDir, schemaName+\".toml\")\n+\tlocalPath := resolveSchemaPath(repoRoot, format.DocumentSchemaDir, strings.TrimSpace(documentID)+\".toml\")\n+\tshared := readSchemaSource(sharedPath, \"builtin:\"+strings.TrimSpace(schemaName))\n+\tlocal := \"none\"\n+\tif strings.TrimSpace(documentID) != \"\" {\n+\t\tlocal = readSchemaSource(localPath, \"missing-local:\"+strings.TrimSpace(documentID))\n+\t}\n+\treturn Hash(struct {\n+\t\tSchemaName string\n+\t\tDocumentID string\n+\t\tShared     string\n+\t\tLocal      string\n+\t}{strings.TrimSpace(schemaName), strings.TrimSpace(documentID), shared, local})\n+}\n+\n+func sameIdentity(left, right Entry) bool {\n+\treturn left.Path == NormalizePath(right.Path) && left.ContentSHA256 == right.ContentSHA256 &&\n+\t\tleft.EngineVersion == right.EngineVersion && left.FrontmatterPolicyHash == right.FrontmatterPolicyHash &&\n+\t\tleft.EffectiveSchemaHash == right.EffectiveSchemaHash && left.ImmutableSnapshotHash == right.ImmutableSnapshotHash\n+}\n+\n+func recordName(path string) string { return prefix + Hash(NormalizePath(path)) }\n+\n+func resolveSchemaPath(repoRoot, configured, name string) string {\n+\tif filepath.IsAbs(configured) {\n+\t\treturn filepath.Join(configured, name)\n+\t}\n+\treturn filepath.Join(repoRoot, filepath.FromSlash(configured), name)\n+}\n+\n+func readSchemaSource(path, fallback string) string {\n+\tdata, err := os.ReadFile(path)\n+\tif err != nil {\n+\t\treturn fallback\n+\t}\n+\treturn ContentHash(data)\n+}\n+\n+func missingPrivateState(repoRoot string) bool {\n+\t_, err := os.Stat(filepath.Join(repoRoot, \".ddocs\", \"HEAD\"))\n+\treturn errors.Is(err, os.ErrNotExist)\n+}\n@@ -0,0 +1,125 @@\n+package validationcache\n+\n+import (\n+\t\"os\"\n+\t\"path/filepath\"\n+\t\"testing\"\n+\n+\t\"github.com/Lokee86/demon-docs/internal/config\"\n+\t\"github.com/Lokee86/demon-docs/internal/ddrepo\"\n+)\n+\n+func TestOpenWithoutPrivateRepositoryDoesNotInitializeState(t *testing.T) {\n+\troot := t.TempDir()\n+\tstore, err := Open(root)\n+\tif err != nil {\n+\t\tt.Fatal(err)\n+\t}\n+\tstore.Merge(Entry{\n+\t\tPath:                  \"docs/guide.md\",\n+\t\tContentSHA256:         ContentHash([]byte(\"content\")),\n+\t\tEngineVersion:         EngineVersion,\n+\t\tFrontmatterPolicyHash: Hash(\"frontmatter\"),\n+\t\tEffectiveSchemaHash:   Hash(\"schema\"),\n+\t\tImmutableSnapshotHash: Hash(nil),\n+\t\tFrontmatterClean:      true,\n+\t})\n+\tif err := store.Save(); err != nil {\n+\t\tt.Fatal(err)\n+\t}\n+\tif _, err := os.Stat(filepath.Join(root, \".ddocs\")); !os.IsNotExist(err) {\n+\t\tt.Fatalf(\"validation cache initialized private state: %v\", err)\n+\t}\n+}\n+\n+func TestRetainDeletesRecordsOutsideActiveScope(t *testing.T) {\n+\troot := t.TempDir()\n+\tif _, err := ddrepo.Init(root); err != nil {\n+\t\tt.Fatal(err)\n+\t}\n+\tidentity := func(path string) Entry {\n+\t\treturn Entry{\n+\t\t\tPath:                  path,\n+\t\t\tContentSHA256:         ContentHash([]byte(path)),\n+\t\t\tEngineVersion:         EngineVersion,\n+\t\t\tFrontmatterPolicyHash: Hash(\"frontmatter\"),\n+\t\t\tEffectiveSchemaHash:   Hash(\"schema\"),\n+\t\t\tImmutableSnapshotHash: Hash(nil),\n+\t\t\tFrontmatterClean:      true,\n+\t\t}\n+\t}\n+\tstore, err := Open(root)\n+\tif err != nil {\n+\t\tt.Fatal(err)\n+\t}\n+\tstore.Merge(identity(\"docs/keep.md\"))\n+\tstore.Merge(identity(\"docs/remove.md\"))\n+\tif err := store.Save(); err != nil {\n+\t\tt.Fatal(err)\n+\t}\n+\tstore, err = Open(root)\n+\tif err != nil {\n+\t\tt.Fatal(err)\n+\t}\n+\tstore.Retain([]string{\"docs/keep.md\"})\n+\tif err := store.Save(); err != nil {\n+\t\tt.Fatal(err)\n+\t}\n+\tstore, err = Open(root)\n+\tif err != nil {\n+\t\tt.Fatal(err)\n+\t}\n+\tkeep := identity(\"docs/keep.md\")\n+\tif _, ok := store.Lookup(keep.Path, keep.ContentSHA256, keep.FrontmatterPolicyHash, keep.EffectiveSchemaHash, keep.ImmutableSnapshotHash); !ok {\n+\t\tt.Fatal(\"active cache record was removed\")\n+\t}\n+\tremoved := identity(\"docs/remove.md\")\n+\tif _, ok := store.Lookup(removed.Path, removed.ContentSHA256, removed.FrontmatterPolicyHash, removed.EffectiveSchemaHash, removed.ImmutableSnapshotHash); ok {\n+\t\tt.Fatal(\"stale cache record remained reachable\")\n+\t}\n+}\n+\n+func TestEntryRoundTripsAndSchemaSourceChangesInvalidate(t *testing.T) {\n+\troot := t.TempDir()\n+\tif _, err := ddrepo.Init(root); err != nil {\n+\t\tt.Fatal(err)\n+\t}\n+\tformat := config.Format{Enabled: true, SchemaDir: \".ddocs/schemas\", DocumentSchemaDir: \".ddocs/document-schemas\"}\n+\tif err := os.MkdirAll(filepath.Join(root, \".ddocs\", \"schemas\"), 0o755); err != nil {\n+\t\tt.Fatal(err)\n+\t}\n+\tschemaPath := filepath.Join(root, \".ddocs\", \"schemas\", \"general.toml\")\n+\tif err := os.WriteFile(schemaPath, []byte(\"name = 'general'\\n\"), 0o644); err != nil {\n+\t\tt.Fatal(err)\n+\t}\n+\tfirstSchemaHash := EffectiveSchemaHash(root, format, \"general\", \"\")\n+\tstore, err := Open(root)\n+\tif err != nil {\n+\t\tt.Fatal(err)\n+\t}\n+\tstore.Merge(Entry{\n+\t\tPath:                  \"docs/Guide.md\",\n+\t\tContentSHA256:         ContentHash([]byte(\"content\")),\n+\t\tEngineVersion:         EngineVersion,\n+\t\tFrontmatterPolicyHash: Hash(\"frontmatter\"),\n+\t\tEffectiveSchemaHash:   firstSchemaHash,\n+\t\tImmutableSnapshotHash: Hash(nil),\n+\t\tFrontmatterClean:      true,\n+\t})\n+\tif err := store.Save(); err != nil {\n+\t\tt.Fatal(err)\n+\t}\n+\treopened, err := Open(root)\n+\tif err != nil {\n+\t\tt.Fatal(err)\n+\t}\n+\tif _, ok := reopened.Lookup(\"docs/guide.md\", ContentHash([]byte(\"content\")), Hash(\"frontmatter\"), firstSchemaHash, Hash(nil)); !ok {\n+\t\tt.Fatal(\"stored validation entry did not round-trip through ddrepo\")\n+\t}\n+\tif err := os.WriteFile(schemaPath, []byte(\"name = 'general'\\ndescription = 'changed'\\n\"), 0o644); err != nil {\n+\t\tt.Fatal(err)\n+\t}\n+\tif EffectiveSchemaHash(root, format, \"general\", \"\") == firstSchemaHash {\n+\t\tt.Fatal(\"schema source change did not change effective schema hash\")\n+\t}\n+}","files":[{"filename":"docs/architecture/INDEX.md","patch":"@@ -37,6 +37,7 @@ Implemented ownership boundaries, state models, reconciliation pipelines, and in\n - [review-ledger.md](review-ledger.md) - Append-only suggestion decisions, applied changes, undo data, repair blocks, policy projection, and Git-backed publication.\n - [review-lifecycles.md](review-lifecycles.md) - Suggestion decisions, staleness, selection, applied changes, undo, repair blocks, and append-only event replay.\n - [stateless-move-transaction.md](stateless-move-transaction.md) - Explicit move planning, path remapping, preflight, rewrite ordering, and best-effort rollback.\n+- [validation-cache.md](validation-cache.md) - Validation Cache documentation.\n - [watch-scheduler.md](watch-scheduler.md) - Debounce state, follow-up runs, mixed-watcher serialization, cancellation, and error propagation.\n <!-- doc-ledger:files:end -->\n "},{"filename":"docs/architecture/validation-cache.md","patch":"@@ -0,0 +1,53 @@\n+---\n+author: brian\n+created: \"2026-07-20\"\n+document_id: 019f7d55-31e4-7d8f-9bb4-4e2d9cf9e6b1\n+document_type: general\n+policy_exempt: false\n+summary: Durable incremental cache for clean frontmatter and document-format validation.\n+---\n+# Validation Cache\n+\n+Parent index: [Architecture](./INDEX.md)\n+\n+## Purpose\n+\n+Frontmatter and document-body format validation use a durable incremental cache for unchanged clean documents. The cache is an optimization boundary: authored Markdown, diagnostics, repair decisions, immutable records, and schema history remain authoritative.\n+\n+## Record identity\n+\n+Each record is stored through `ddrepo` under `.ddocs/` and is addressed by the normalized repository-relative path. A record is reusable only when all of these values match:\n+\n+- normalized path;\n+- raw document content SHA-256;\n+- validation engine version;\n+- effective frontmatter policy hash;\n+- effective selected shared/document schema hash; and\n+- the immutable-value snapshot used by frontmatter validation.\n+\n+The selected schema identity is retained in the record so an unchanged document can verify the current shared and document-specific schema sources without reparsing its Markdown frontmatter. Shared and document-specific schema source changes therefore invalidate the record; changing the engine version also invalidates all records.\n+\n+## Clean-only reuse\n+\n+Only a document with no diagnostics and no pending repair is recorded as clean. A cache hit restores no authored output; it contributes the same empty diagnostic result and skips document parsing and evaluation. Format schema loading and private-state bookkeeping still occur where needed for history publication.\n+\n+Frontmatter cache candidates retain the document ID and immutable values needed to preserve duplicate-ID detection and immutable publication. If duplicate IDs are present, all affected candidates are reparsed before evaluation. A fix can also publish immutable values retained by a clean check cache hit.\n+\n+YAML and TOML behavior, diagnostic ordering, and deterministic repair ordering are unchanged. Cache failure is an operational error because a corrupt or unavailable private-state repository must not be silently mistaken for durable validation state.\n+\n+## Mutation boundary\n+\n+`check` may update cache records only when the repository already has an initialized `.ddocs` private object store; standalone checks do not initialize one merely to persist cache data. It never writes authored Markdown or schema files. `fix` writes the same cache records in addition to its existing guarded authored-file and immutable-state publication. Cache records use the existing `ddrepo` transaction and do not create commits on the user's normal Git branch.\n+\n+Each validation pass also removes cache records whose normalized paths are no longer in the active Markdown scope. A rename or deletion therefore does not leave permanently reachable stale records.\n+\n+## Related docs\n+\n+- [Front Matter Schemas](../reference/frontmatter.md)\n+- [Document Schemas And Format Enforcement](../reference/document-schemas.md)\n+- [Managed Files and State](../reference/managed-files-and-state.md)\n+- [Private Object Repository](private-object-repository.md)\n+\n+## Notes\n+\n+The cache is an optimization over authoritative source and private-state records; deleting it is safe after active validation processes have stopped, although the next validation pass reparses every document."},{"filename":"docs/development/behavioral-contract-matrix.md","patch":"@@ -64,6 +64,7 @@ A test passing does not authorize undocumented contract changes. A document clai\n | YAML and TOML frontmatter parse and render deterministically while preserving the body | [Front Matter Schemas](../reference/frontmatter.md) | `parse_test.go`, `TestParseSupportsYAMLAndTOMLAndPreservesBody`, `TestRenderPreservesSelectedFormatAndSortsFields` | `go test ./internal/frontmatter -count=1` |\n | Unknown-field policy, configured sources, immutable values, and conditional requirements remain explicit | [Front Matter Schemas](../reference/frontmatter.md) | `evaluate_test.go`, `TestUnknownFieldModes`, `TestEvaluateRestoresRecordedImmutableValue`, `TestConditionalRuleCanRemainUnresolvedOrUseConfiguredSource` | `go test ./internal/frontmatter -count=1` |\n | Frontmatter plans stay inside the docs root, detect duplicate document IDs, preserve source encoding, and converge on repeat apply | [Front Matter Schemas](../reference/frontmatter.md) | `plan_test.go`, `TestBuildApplyIsIdempotentPreservesCRLFAndKeepsIDAcrossMove`, `TestBuildStaysInsideDocsRootAndDetectsDuplicateIDs` | `go test ./internal/frontmatter ./internal/filetxn -count=1` |\n+| Unchanged clean frontmatter and document-format validation skips document parsing/evaluation while content, policy, schema, engine, immutable, and duplicate-identity changes invalidate reuse | [Validation Cache](../architecture/validation-cache.md) | `validation_cache_test.go` in `internal/validationcache`, `internal/frontmatter`, and `internal/documentpolicy` | `go test ./internal/validationcache ./internal/frontmatter ./internal/documentpolicy -count=1` |\n | Metadata selects a document schema before path fallback and schema validation rejects unsafe hierarchy or ambiguous aliases | [Document Schemas And Format Enforcement](../reference/document-schemas.md) | `TestSchemaSelectionUsesMetadataBeforePathFallback`, `TestSchemaValidationRejectsCyclesAndAmbiguousSiblingHeadings` | `go test ./internal/documentpolicy -count=1` |\n | Unknown or duplicate human-authored sections block automatic body mutation until an explicit resolution is recorded | [Document Schemas And Format Enforcement](../reference/document-schemas.md) | `TestUnknownSectionBlocksFix`, app integration tests for ignore/merge/delete | `go test ./internal/documentpolicy ./internal/app -count=1` |\n | Stable section IDs drive deterministic heading renames and cumulative document-specific schema invalidation | [Document Schemas And Format Enforcement](../reference/document-schemas.md) | `TestSchemaRenameUsesStableSectionID`, migration tests in `document_policy_migration_test.go` | `go test ./internal/documentpolicy ./internal/app -count=1` |"},{"filename":"docs/development/documentation-coverage.md","patch":"@@ -60,6 +60,7 @@ The root README and roadmap are entry and status documents. They do not satisfy\n | `internal/ignore/` | `.docignore` policies, nested domains, permanent exclusions | [Ignore and Traversal](../architecture/ignore-and-traversal.md), [Configuration Reference](../reference/configuration.md) |\n | `internal/ddrepo/` | Private Git-object repository, codecs, transactions | [Private Object Repository](../architecture/private-object-repository.md), [Repository State and Transactions](../architecture/repository-state-and-transactions.md), [Managed Files and State](../reference/managed-files-and-state.md) |\n | `internal/frontmatter/` | YAML/TOML parsing, schema evaluation, deterministic repair, duplicate identity detection, and immutable-value publication | [Front Matter Schemas](../reference/frontmatter.md), [Reconciliation Command Lifecycle](../architecture/reconciliation-command-lifecycle.md), [Generated Rewrite Publication](../architecture/generated-rewrite-publication.md) |\n+| `internal/validationcache/` | Durable normalized-path cache records and content/policy/schema identity invalidation for clean validation | [Validation Cache](../architecture/validation-cache.md), [Managed Files and State](../reference/managed-files-and-state.md) |\n | `internal/documentpolicy/` | Document-schema selection, Markdown body classification/enforcement, explicit conflict operations, schema-based creation, codemap placement, and schema-history state | [Document Schemas And Format Enforcement](../reference/document-schemas.md), [Reconciliation Command Lifecycle](../architecture/reconciliation-command-lifecycle.md), [Codemap Managed Execution](../architecture/codemap-managed-execution.md) |\n \n ## Documentation reconciliation coverage"},{"filename":"docs/reference/document-schemas.md","patch":"@@ -125,6 +125,8 @@ ddocs watch --format\n \n `--docs` is the umbrella selector for folder indexes, frontmatter, and body format. `--frontmatter` and `--format` select the two policy operations independently.\n \n+Clean body-format results participate in the durable validation cache. Entries are reused only when the document content, validation engine, effective frontmatter policy, and effective selected shared/document schema hashes match. Editing either the shared schema or the document-specific schema invalidates the affected entry. Cache state is private `.ddocs/` state; `check` does not write authored Markdown or schema files.\n+\n The format parser uses ordinary Markdown symbols. It does not add or require managed-region markers. Headings inside fenced code, blockquotes, and HTML blocks are ignored completely.\n \n `check` reports violations without writing. `fix` may:"},{"filename":"docs/reference/frontmatter.md","patch":"@@ -147,6 +147,12 @@ The required field must exist and be non-empty when the condition matches. Other\n \n `check` never modifies documents.\n \n+## Incremental validation cache\n+\n+Unchanged clean documents may be served from the durable validation cache under `.ddocs/`. A reusable entry requires the normalized path, content SHA-256, validation engine version, effective frontmatter policy hash, selected shared/document schema hash, and the current immutable-value snapshot to match. Only zero-diagnostic documents are cached. Duplicate document IDs and immutable changes invalidate or bypass reuse, so cache hits do not suppress those diagnostics.\n+\n+`check` may write cache records inside an already initialized `.ddocs/` store; it does not initialize private state for a standalone repository and does not write authored Markdown, schema inputs, or generated document content. Content, policy, schema, immutable-state, or engine changes invalidate the entry automatically, and records for documents no longer in scope are removed.\n+\n ## Check and fix behavior\n \n Front matter runs with the documentation system during default reconciliation and `--docs` selection."},{"filename":"docs/reference/managed-files-and-state.md","patch":"@@ -138,6 +138,7 @@ configuration\n object and identity records\n path history and fingerprints\n recorded immutable frontmatter values\n+incremental frontmatter and document-format validation cache records\n shared schema history used for deterministic heading migrations\n human-authored shared schemas under `schemas/`\n human-editable document-specific schemas under `document-schemas/`"},{"filename":"internal/documentpolicy/plan.go","patch":"@@ -13,6 +13,7 @@ import (\n \t\"github.com/Lokee86/demon-docs/internal/frontmatter\"\n \t\"github.com/Lokee86/demon-docs/internal/model\"\n \t\"github.com/Lokee86/demon-docs/internal/repository\"\n+\t\"github.com/Lokee86/demon-docs/internal/validationcache\"\n )\n \n type Diagnostic struct {\n@@ -33,6 +34,7 @@ type Plan struct {\n \tblockedHistory     map[string]bool\n \tblockAllHistory    bool\n \trepositoryRoot     string\n+\tcacheHits          int\n }\n \n func Build(repoRoot, docsRoot string, cfg config.Config, repair bool) (Plan, error) {\n@@ -63,6 +65,19 @@ func Build(repoRoot, docsRoot string, cfg config.Config, repair bool) (Plan, err\n \tif err != nil {\n \t\treturn plan, err\n \t}\n+\tcache, err := validationcache.Open(repoRoot)\n+\tif err != nil {\n+\t\treturn plan, fmt.Errorf(\"open validation cache: %w\", err)\n+\t}\n+\tactivePaths := make([]string, 0, len(files))\n+\tfor _, path := range files {\n+\t\trelative, relativeErr := filepath.Rel(repoRoot, path)\n+\t\tif relativeErr == nil {\n+\t\t\tactivePaths = append(activePaths, filepath.ToSlash(relative))\n+\t\t}\n+\t}\n+\tcache.Retain(activePaths)\n+\tpolicyHash := validationcache.FrontmatterPolicyHash(cfg)\n \tfor _, path := range files {\n \t\trelative, _ := filepath.Rel(repoRoot, path)\n \t\trelative = filepath.ToSlash(relative)\n@@ -71,6 +86,24 @@ func Build(repoRoot, docsRoot string, cfg config.Config, repair bool) (Plan, err\n \t\t\treturn plan, err\n \t\t}\n \t\tsource := string(data)\n+\t\tcontentHash := validationcache.ContentHash(data)\n+\t\tcandidate, hasCandidate := cache.Candidate(relative, contentHash, policyHash)\n+\t\tif hasCandidate && candidate.FormatClean && candidate.SchemaName != \"\" {\n+\t\t\tschemaHash := validationcache.EffectiveSchemaHash(repoRoot, cfg.Format, candidate.SchemaName, candidate.DocumentID)\n+\t\t\tif _, valid := cache.Lookup(relative, contentHash, policyHash, schemaHash, candidate.ImmutableSnapshotHash); valid {\n+\t\t\t\tshared, _, loadErr := LoadShared(repoRoot, cfg.Format, candidate.SchemaName)\n+\t\t\t\tif loadErr != nil {\n+\t\t\t\t\tplan.Diagnostics = append(plan.Diagnostics, Diagnostic{Path: relative, Message: loadErr.Error()})\n+\t\t\t\t\tcontinue\n+\t\t\t\t}\n+\t\t\t\tplan.history[candidate.SchemaName] = shared\n+\t\t\t\tif _, _, historyErr := loadSchemaHistory(repoRoot, candidate.SchemaName); historyErr != nil {\n+\t\t\t\t\treturn plan, historyErr\n+\t\t\t\t}\n+\t\t\t\tplan.cacheHits++\n+\t\t\t\tcontinue\n+\t\t\t}\n+\t\t}\n \t\tparsed, err := frontmatter.Parse(source, cfg.Frontmatter.AllowedFormats)\n \t\tif err != nil {\n \t\t\tplan.Diagnostics = append(plan.Diagnostics, Diagnostic{Path: relative, Message: err.Error()})\n@@ -97,6 +130,7 @@ func Build(repoRoot, docsRoot string, cfg config.Config, repair bool) (Plan, err\n \t\t\treturn plan, err\n \t\t}\n \t\tdocumentID, _ := parsed.Values[\"document_id\"].(string)\n+\t\tdocumentType, _ := parsed.Values[\"document_type\"].(string)\n \t\tlocal := DocumentSchema{}\n \t\tlocalPath := \"\"\n \t\tlocalExists := false\n@@ -193,6 +227,20 @@ func Build(repoRoot, docsRoot string, cfg config.Config, repair bool) (Plan, err\n \t\t\t\tplan.rewrites = append(plan.rewrites, filetxn.New(path, data, []byte(next)))\n \t\t\t}\n \t\t}\n+\t\tif len(result.Diagnostics) == 0 && !result.Changed {\n+\t\t\tcache.Merge(validationcache.Entry{\n+\t\t\t\tPath:                  relative,\n+\t\t\t\tContentSHA256:         contentHash