source[i] != '[' || escaped(source, i) || i+1 < len(source) && source[i+1] == '[' {\n+\t\t\ti++\n+\t\t\tcontinue\n+\t\t}\n+\t\tfirstEnd := referenceBracketEnd(source, i+1)\n+\t\tif firstEnd < 0 || firstEnd+1 >= len(source) || source[firstEnd+1] != '[' {\n+\t\t\ti++\n+\t\t\tcontinue\n+\t\t}\n+\t\tsecondEnd := referenceBracketEnd(source, firstEnd+2)\n+\t\tif secondEnd < 0 {\n+\t\t\ti++\n+\t\t\tcontinue\n+\t\t}\n+\t\tlabelStart, labelEnd := firstEnd+2, secondEnd\n+\t\tlabel := source[labelStart:labelEnd]\n+\t\tif label == \"\" {\n+\t\t\tlabelStart, labelEnd = i+1, firstEnd\n+\t\t\tlabel = source[labelStart:labelEnd]\n+\t\t}\n+\t\tnormalized := normalizeReferenceLabel(label)\n+\t\tif normalized != \"\" && !definitions[normalized] {\n+\t\t\tline, column := sourcePosition(source, labelStart)\n+\t\t\tresult = append(result, undefinedReference{\n+\t\t\t\tStart: labelStart, End: labelEnd, Line: line, Column: column, Label: label,\n+\t\t\t})\n+\t\t}\n+\t\ti = secondEnd + 1\n+\t}\n+\treturn result\n+}\n+\n+func referenceDefinitionLabels(source string, protected []byteRange) map[string]bool {\n+\tresult := map[string]bool{}\n+\tfor lineStart := 0; lineStart <= len(source); {\n+\t\tlineEnd := strings.IndexByte(source[lineStart:], '\\n')\n+\t\tif lineEnd < 0 {\n+\t\t\tlineEnd = len(source)\n+\t\t} else {\n+\t\t\tlineEnd += lineStart\n+\t\t}\n+\t\tif !inRanges(lineStart, protected) {\n+\t\t\tline := source[lineStart:lineEnd]\n+\t\t\tindent := 0\n+\t\t\tfor indent < len(line) && indent < 4 && line[indent] == ' ' {\n+\t\t\t\tindent++\n+\t\t\t}\n+\t\t\tif indent <= 3 && indent < len(line) && line[indent] == '[' {\n+\t\t\t\tclose := referenceBracketEnd(line, indent+1)\n+\t\t\t\tif close >= 0 && close+1 < len(line) && line[close+1] == ':' {\n+\t\t\t\t\tlabel := normalizeReferenceLabel(line[indent+1 : close])\n+\t\t\t\t\tif label != \"\" {\n+\t\t\t\t\t\tresult[label] = true\n+\t\t\t\t\t}\n+\t\t\t\t}\n+\t\t\t}\n+\t\t}\n+\t\tif lineEnd == len(source) {\n+\t\t\tbreak\n+\t\t}\n+\t\tlineStart = lineEnd + 1\n+\t}\n+\treturn result\n+}\n+\n+func referenceBracketEnd(source string, start int) int {\n+\tfor i := start; i < len(source); i++ {\n+\t\tif source[i] == '\\n' || source[i] == '\\r' {\n+\t\t\treturn -1\n+\t\t}\n+\t\tif source[i] == ']' && !escaped(source, i) {\n+\t\t\treturn i\n+\t\t}\n+\t}\n+\treturn -1\n+}\n+\n+func normalizeReferenceLabel(label string) string {\n+\treturn strings.ToLower(strings.Join(strings.Fields(label), \" \"))\n+}"},{"filename":"internal/links/syntax_targets.go","patch":"@@ -0,0 +1,71 @@\n+package links\n+\n+import (\n+\t\"path/filepath\"\n+\t\"strings\"\n+)\n+\n+func exactTargetForSyntax(inventory *inventory, resolved, syntax string) (*FileRecord, string) {\n+\trecord, actual := inventory.exact(resolved)\n+\tif record != nil || syntax != \"wiki\" || filepath.Ext(resolved) != \"\" {\n+\t\treturn record, actual\n+\t}\n+\tif record, actual = inventory.exact(wikiResolvedPath(resolved)); record != nil {\n+\t\treturn record, actual\n+\t}\n+\tcandidates := inventory.candidates(filepath.Base(wikiResolvedPath(resolved)), \"file\")\n+\tif len(candidates) == 1 {\n+\t\treturn inventory.exact(candidates[0])\n+\t}\n+\treturn nil, \"\"\n+}\n+\n+func targetCaseMismatch(syntax, resolved, actual string) bool {\n+\texpected := expectedTargetPath(syntax, resolved)\n+\tif filepath.Clean(actual) == filepath.Clean(expected) {\n+\t\treturn false\n+\t}\n+\tif strings.EqualFold(filepath.Clean(actual), filepath.Clean(expected)) {\n+\t\treturn true\n+\t}\n+\treturn syntax != \"wiki\" || filepath.Ext(resolved) != \"\"\n+}\n+\n+func expectedTargetPath(syntax, resolved string) string {\n+\tif syntax == \"wiki\" && filepath.Ext(resolved) == \"\" {\n+\t\treturn wikiResolvedPath(resolved)\n+\t}\n+\treturn resolved\n+}\n+\n+func candidatePathsForSyntax(inventory *inventory, resolved, preferredID, syntax string) []string {\n+\tif syntax == \"wiki\" && filepath.Ext(resolved) == \"\" {\n+\t\treturn candidatePaths(inventory, wikiResolvedPath(resolved), preferredID)\n+\t}\n+\treturn candidatePaths(inventory, resolved, preferredID)\n+}\n+\n+func renderTargetForSyntax(syntax, originalPath string, style targetStyle, sourcePath, targetPath string) string {\n+\tif syntax == \"wiki\" && originalPath == \"\" && filepath.Clean(sourcePath) == filepath.Clean(targetPath) {\n+\t\treturn \"\"\n+\t}\n+\tif syntax == \"wiki\" && isBareWikiPath(originalPath) {\n+\t\treturn strings.TrimSuffix(filepath.Base(targetPath), filepath.Ext(targetPath))\n+\t}\n+\trendered := renderTargetPath(style, originalPath, sourcePath, targetPath)\n+\tif syntax == \"wiki\" && filepath.Ext(originalPath) == \"\" && strings.EqualFold(filepath.Ext(rendered), \".md\") {\n+\t\trendered = strings.TrimSuffix(rendered, filepath.Ext(rendered))\n+\t}\n+\treturn rendered\n+}\n+\n+func isBareWikiPath(path string) bool {\n+\treturn path != \"\" && filepath.Ext(path) == \"\" && !strings.ContainsAny(path, `/\\`)\n+}\n+\n+func wikiResolvedPath(path string) string {\n+\tif filepath.Ext(path) == \"\" {\n+\t\treturn path + \".md\"\n+\t}\n+\treturn path\n+}"},{"filename":"internal/links/wiki_links.go","patch":"@@ -0,0 +1,48 @@\n+package links\n+\n+import \"strings\"\n+\n+func parseWikiLinks(source string, protected []byteRange) []occurrence {\n+\tvar result []occurrence\n+\tfor i := 0; i+1 < len(source); {\n+\t\tif end, ok := rangeEnd(i, protected); ok {\n+\t\t\ti = end\n+\t\t\tcontinue\n+\t\t}\n+\t\tif source[i] != '[' || source[i+1] != '[' || escaped(source, i) {\n+\t\t\ti++\n+\t\t\tcontinue\n+\t\t}\n+\t\tclose := strings.Index(source[i+2:], \"]]\")\n+\t\tif close < 0 {\n+\t\t\ti += 2\n+\t\t\tcontinue\n+\t\t}\n+\t\tcontentStart := i + 2\n+\t\tcontentEnd := contentStart + close\n+\t\tif strings.ContainsAny(source[contentStart:contentEnd], \"\\r\\n\") {\n+\t\t\ti += 2\n+\t\t\tcontinue\n+\t\t}\n+\t\ttargetEnd := contentEnd\n+\t\tif pipe := strings.IndexByte(source[contentStart:contentEnd], '|'); pipe >= 0 {\n+\t\t\ttargetEnd = contentStart + pipe\n+\t\t}\n+\t\tfor contentStart < targetEnd && isHTMLSpace(source[contentStart]) {\n+\t\t\tcontentStart++\n+\t\t}\n+\t\tfor targetEnd > contentStart && isHTMLSpace(source[targetEnd-1]) {\n+\t\t\ttargetEnd--\n+\t\t}\n+\t\tif targetEnd > contentStart {\n+\t\t\trawPath, suffix := splitSuffix(source[contentStart:targetEnd])\n+\t\t\tline, column := sourcePosition(source, contentStart)\n+\t\t\tresult = append(result, occurrence{\n+\t\t\t\tStart: contentStart, End: contentStart + len(rawPath), Line: line, Column: column,\n+\t\t\t\tRawPath: rawPath, Suffix: suffix, Syntax: \"wiki\",\n+\t\t\t})\n+\t\t}\n+\t\ti = contentEnd + 2\n+\t}\n+\treturn result\n+}"},{"filename":"internal/watch/watch.go","patch":"@@ -67,7 +67,7 @@ func RootSelected(ctx context.Context, docsRoot, repositoryRoot string, c config\n \tvar externalDirectories []string\n \trun := func() error {\n \t\tchanged := 0\n-\t\tmessages := 0\n+\t\tvar diagnostics []string\n \t\tunresolved := 0\n \t\tif features.Indexes {\n \t\t\tresult, err := reconcile.TreeWithIgnoreRoot(docsRoot, repositoryRoot, c)\n@@ -79,7 +79,7 @@ func RootSelected(ctx context.Context, docsRoot, repositoryRoot string, c config\n \t\t\t\treturn err\n \t\t\t}\n \t\t\tchanged += count\n-\t\t\tmessages += len(result.Messages)\n+\t\t\tdiagnostics = append(diagnostics, result.Messages...)\n \t\t}\n \t\tif features.Links {\n \t\t\tplan, err := links.Reconcile(repositoryRoot)\n@@ -91,7 +91,7 @@ func RootSelected(ctx context.Context, docsRoot, repositoryRoot string, c config\n \t\t\t\treturn err\n \t\t\t}\n \t\t\tchanged += count\n-\t\t\tmessages += len(plan.Messages)\n+\t\t\tdiagnostics = append(diagnostics, plan.Messages...)\n \t\t\tunresolved = plan.Unresolved\n \t\t\texternalDirectories = externalWatchDirectories(plan.Files)\n \t\t\tif watcher != nil {\n@@ -101,8 +101,8 @@ func RootSelected(ctx context.Context, docsRoot, repositoryRoot string, c config\n \t\t\t}\n \t\t}\n \t\tfmt.Fprintf(out, \"%s ddocs watch updated %d file(s)\\n\", timestamp(), changed)\n-\t\tif messages > 0 {\n-\t\t\tfmt.Fprintf(out, \"%s ddocs watch reconciliation messages: %d\\n\", timestamp(), messages)\n+\t\tfor _, message := range diagnostics {\n+\t\t\tfmt.Fprintf(out, \"%s ddocs watch: %s\\n\", timestamp(), message)\n \t\t}\n \t\tif unresolved > 0 {\n \t\t\tfmt.Fprintf(out, \"%s ddocs watch unresolved links: %d\\n\", timestamp(), unresolved)"},{"filename":"internal/watch/watch_test.go","patch":"@@ -1,6 +1,7 @@\n package watch\n \n import (\n+\t\"bytes\"\n \t\"context\"\n \t\"os\"\n \t\"path/filepath\"\n@@ -84,6 +85,24 @@ func TestWatchConvergesWithoutSelfWriteLoop(t *testing.T) {\n \t}\n }\n \n+func TestWatchPrintsActualReconciliationMessages(t *testing.T) {\n+\troot := t.TempDir()\n+\tif err := os.WriteFile(filepath.Join(root, \"README.md\"), []byte(\"[missing](missing.md)\\n\"), 0o644); err != nil {\n+\t\tt.Fatal(err)\n+\t}\n+\tvar out bytes.Buffer\n+\tif err := RootSelected(context.Background(), root, root, config.Default(), Features{Links: true}, nil, true, &out); err != nil {\n+\t\tt.Fatal(err)\n+\t}\n+\ttext := out.String()\n+\tif !strings.Contains(text, \"Broken link in README.md\") {\n+\t\tt.Fatalf(\"watch output did not include the diagnostic: %q\", text)\n+\t}\n+\tif strings.Contains(text, \"reconciliation messages:\") {\n+\t\tt.Fatalf(\"watch output still used the opaque count: %q\", text)\n+\t}\n+}\n+\n func waitFor(t *testing.T, timeout time.Duration, ready func() bool) {\n \tt.Helper()\n \tdeadline := time.Now().Add(timeout)"}],"repository_full_name":"Lokee86/demon-docs","comments":null,"author":{"login":"Lokee86","name":null,"email":null,"avatar_url":"https://avatars.githubusercontent.com/u/176702987?v=4","id":176702987},"committer":{"login":"Lokee86","name":null,"email":null,"avatar_url":"https://avatars.githubusercontent.com/u/176702987?v=4","id":176702987},"created_at":"2026-07-19T19:58:57Z","git_author_email":null,"display_url":"https://github.com/Lokee86/demon-docs/commit/1fa508b552bef06885ea92855d1e92ca09c70cca","display_title":"Expand link syntax diagnostics"},"url":"https://github.com/Lokee86/demon-docs/commit/1fa508b552bef06885ea92855d1e92ca09c70cca","title":"Expand link syntax diagnostics","diff":"@@ -25,10 +25,18 @@ The link scanner handles:\n \n - inline links such as `[Guide](guide.md)`;\n - images such as `![Diagram](assets/diagram.png)`;\n-- angle-wrapped destinations such as `[File](<files/a b.pdf>)`; and\n-- reference definitions such as `[guide]: docs/guide.md`.\n+- angle-wrapped destinations such as `[File](<files/a b.pdf>)`;\n+- reference definitions such as `[guide]: docs/guide.md`;\n+- path-based wiki links such as `[[guide]]`, `[[docs/guide|Guide]]`, and `![[assets/diagram.png]]`; and\n+- local HTML targets in common `href`, `src`, and `poster` attributes.\n \n-Link-like text inside fenced code blocks and inline code spans is ignored. Heading fragments and query strings are preserved when a path is rewritten. Heading-anchor existence is not yet validated. HTML links, wiki-link syntax, and undefined reference labels are outside this first implementation.\n+Extensionless wiki targets resolve as Markdown files. A unique matching Markdown basename elsewhere in the repository is accepted for Obsidian-style wiki links; ambiguous matches are reported and left unchanged. Wiki aliases and embed markers are preserved during repair.\n+\n+Explicit and collapsed reference uses such as `[Guide][guide]` and `[guide][]` are checked against reference definitions. Missing labels are reported as unresolved links. Shortcut references such as `[guide]` remain untreated because they are indistinguishable from ordinary bracketed prose without a definition.\n+\n+HTML target coverage includes `a[href]`, `link[href]`, `img[src]`, `script[src]`, `source[src]`, `video[src]`, `video[poster]`, `audio[src]`, and `iframe[src]`.\n+\n+Link-like text inside fenced code blocks and inline code spans is ignored. Heading fragments and query strings are preserved when a path is rewritten. Heading-anchor existence is not yet validated.\n \n ## Persistent State\n \n@@ -103,7 +111,7 @@ ddocs watch -l\n \n Supplying both selectors runs both systems, the same as supplying neither.\n \n-`check` reports pending rewrites, broken links, ambiguous links, and missing baseline state without modifying files. `fix` applies repository-contained source rewrites and saves the resulting state. `watch` uses the same reconciliation path automatically after relevant filesystem events.\n+`check` reports pending rewrites, broken links, ambiguous links, undefined reference labels, and missing baseline state without modifying files. `fix` applies repository-contained source rewrites and saves the resulting state. `watch` uses the same reconciliation path automatically after relevant filesystem events and prints each reconciliation diagnostic rather than only a message count.\n \n When links are enabled, watch mode observes the repository root because moves of non-Markdown targets can require Markdown updates. It also watches the nearest existing parent directories of explicitly linked external targets, so an external rename or removal can trigger the same bounded reconciliation attempt. Index-only watch mode remains scoped to the configured docs root.\n \n@@ -0,0 +1,150 @@\n+package links\n+\n+import \"strings\"\n+\n+func parseHTMLLinks(source string, protected []byteRange) []occurrence {\n+\tvar result []occurrence\n+\tfor i := 0; i < len(source); {\n+\t\tif end, ok := rangeEnd(i, protected); ok {\n+\t\t\ti = end\n+\t\t\tcontinue\n+\t\t}\n+\t\tif source[i] != '<' {\n+\t\t\ti++\n+\t\t\tcontinue\n+\t\t}\n+\t\tend := htmlTagEnd(source, i)\n+\t\tif end < 0 {\n+\t\t\ti++\n+\t\t\tcontinue\n+\t\t}\n+\t\tresult = append(result, htmlTagLinks(source, i, end)...)\n+\t\ti = end + 1\n+\t}\n+\treturn result\n+}\n+\n+func htmlTagEnd(source string, start int) int {\n+\tquote := byte(0)\n+\tfor i := start + 1; i < len(source); i++ {\n+\t\tif quote != 0 {\n+\t\t\tif source[i] == quote {\n+\t\t\t\tquote = 0\n+\t\t\t}\n+\t\t\tcontinue\n+\t\t}\n+\t\tif source[i] == '\\'' || source[i] == '\"' {\n+\t\t\tquote = source[i]\n+\t\t\tcontinue\n+\t\t}\n+\t\tif source[i] == '>' {\n+\t\t\treturn i\n+\t\t}\n+\t}\n+\treturn -1\n+}\n+\n+func htmlTagLinks(source string, start, end int) []occurrence {\n+\ti := start + 1\n+\tfor i < end && isHTMLSpace(source[i]) {\n+\t\ti++\n+\t}\n+\tif i >= end || source[i] == '/' || source[i] == '!' || source[i] == '?' {\n+\t\treturn nil\n+\t}\n+\ttagStart := i\n+\tfor i < end && isHTMLName(source[i]) {\n+\t\ti++\n+\t}\n+\ttag := strings.ToLower(source[tagStart:i])\n+\tif tag == \"\" {\n+\t\treturn nil\n+\t}\n+\tvar result []occurrence\n+\tfor i < end {\n+\t\tfor i < end && isHTMLSpace(source[i]) {\n+\t\t\ti++\n+\t\t}\n+\t\tif i >= end || source[i] == '/' {\n+\t\t\tbreak\n+\t\t}\n+\t\tnameStart := i\n+\t\tfor i < end && isHTMLName(source[i]) {\n+\t\t\ti++\n+\t\t}\n+\t\tif nameStart == i {\n+\t\t\ti++\n+\t\t\tcontinue\n+\t\t}\n+\t\tname := strings.ToLower(source[nameStart:i])\n+\t\tfor i < end && isHTMLSpace(source[i]) {\n+\t\t\ti++\n+\t\t}\n+\t\tif i >= end || source[i] != '=' {\n+\t\t\tcontinue\n+\t\t}\n+\t\ti++\n+\t\tfor i < end && isHTMLSpace(source[i]) {\n+\t\t\ti++\n+\t\t}\n+\t\tif i >= end {\n+\t\t\tbreak\n+\t\t}\n+\t\tvalueStart, valueEnd := htmlAttributeValue(source, i, end)\n+\t\ti = valueEnd\n+\t\tif i < end && (source[i] == '\\'' || source[i] == '\"') {\n+\t\t\ti++\n+\t\t}\n+\t\tif valueEnd <= valueStart || !isHTMLTargetAttribute(tag, name) {\n+\t\t\tcontinue\n+\t\t}\n+\t\trawPath, suffix := splitSuffix(source[valueStart:valueEnd])\n+\t\tline, column := sourcePosition(source, valueStart)\n+\t\tresult = append(result, occurrence{\n+\t\t\tStart: valueStart, End: valueStart + len(rawPath), Line: line, Column: column,\n+\t\t\tRawPath: rawPath, Suffix: suffix, Syntax: \"html\",\n+\t\t})\n+\t}\n+\treturn result\n+}\n+\n+func htmlAttributeValue(source string, start, end int) (int, int) {\n+\tif source[start] == '\\'' || source[start] == '\"' {\n+\t\tquote := source[start]\n+\t\tstart++\n+\t\ti := start\n+\t\tfor i < end && source[i] != quote {\n+\t\t\ti++\n+\t\t}\n+\t\treturn start, i\n+\t}\n+\ti := start\n+\tfor i < end && !isHTMLSpace(source[i]) && source[i] != '>' && source[i] != '/' {\n+\t\ti++\n+\t}\n+\treturn start, i\n+}\n+\n+func isHTMLTargetAttribute(tag, name string) bool {\n+\tswitch name {\n+\tcase \"href\":\n+\t\treturn tag == \"a\" || tag == \"link\"\n+\tcase \"src\":\n+\t\tswitch tag {\n+\t\tcase \"img\", \"script\", \"source\", \"video\", \"audio\", \"iframe\":\n+\t\t\treturn true\n+\t\t}\n+\tcase \"poster\":\n+\t\treturn tag == \"video\"\n+\t}\n+\treturn false\n+}\n+\n+func isHTMLSpace(value byte) bool {\n+\treturn value == ' ' || value == '\\t' || value == '\\n' || value == '\\r'\n+}\n+\n+func isHTMLName(value byte) bool {\n+\treturn value >= 'a' && value <= 'z' || value >= 'A' && value <= 'Z' ||\n+\t\tvalue >= '0' && value <= '9' || value == '-' || value == ':' || value == '_'\n+}\n@@ -5,15 +5,16 @@ import \"github.com/Lokee86/demon-docs/internal/model\"\n const schemaVersion = 2\n \n type FileRecord struct {\n-\tID               string   `json:\"id\"`\n-\tPath             string   `json:\"path\"`\n-\tScope            string   `json:\"scope\"`\n-\tKind             string   `json:\"kind\"`\n-\tPresent          bool     `json:\"present\"`\n-\tFingerprint      string   `json:\"fingerprint,omitempty\"`\n-\tSize             int64    `json:\"size,omitempty\"`\n-\tModifiedUnixNano int64    `json:\"modified_unix_nano,omitempty\"`\n-\tPathHistory      []string `json:\"path_history,omitempty\"`\n+\tID                string   `json:\"id\"`\n+\tPath              string   `json:\"path\"`\n+\tScope             string   `json:\"scope\"`\n+\tKind              string   `json:\"kind\"`\n+\tPresent           bool     `json:\"present\"`\n+\tFingerprint       string   `json:\"fingerprint,omitempty\"`\n+\tSize              int64    `json:\"size,omitempty\"`\n+\tModifiedUnixNano  int64    `json:\"modified_unix_nano,omitempty\"`\n+\tPathHistor