turn fmt.Errorf(\"move source changed after planning: %s\", plan.Source)\n+\t}\n+\tif pathKey(plan.Source) != pathKey(plan.Destination) {\n+\t\tif _, err := os.Stat(plan.Destination); err == nil {\n+\t\t\treturn fmt.Errorf(\"move destination appeared after planning: %s\", plan.Destination)\n+\t\t} else if !os.IsNotExist(err) {\n+\t\t\treturn fmt.Errorf(\"stat move destination %s: %w\", plan.Destination, err)\n+\t\t}\n+\t}\n+\tfor _, item := range plan.rewrites {\n+\t\tcurrent, err := os.ReadFile(item.originPath)\n+\t\tif err != nil {\n+\t\t\treturn fmt.Errorf(\"read planned move rewrite %s: %w\", item.originPath, err)\n+\t\t}\n+\t\tif actual := sha256Digest(current); actual != item.rewrite.ExpectedOldSHA256 {\n+\t\t\treturn fmt.Errorf(\"planned move rewrite source changed before apply %s: expected %s, got %s\", item.originPath, item.rewrite.ExpectedOldSHA256, actual)\n+\t\t}\n+\t}\n+\treturn nil\n+}\n+\n+func renameMovePath(source, destination string) error {\n+\tif pathKey(source) == pathKey(destination) && filepath.Clean(source) != filepath.Clean(destination) {\n+\t\ttemporary, err := os.MkdirTemp(filepath.Dir(source), \".ddocs-case-move-*\")\n+\t\tif err != nil {\n+\t\t\treturn err\n+\t\t}\n+\t\tif err := os.Remove(temporary); err != nil {\n+\t\t\treturn err\n+\t\t}\n+\t\tif err := os.Rename(source, temporary); err != nil {\n+\t\t\treturn err\n+\t\t}\n+\t\tif err := os.Rename(temporary, destination); err != nil {\n+\t\t\t_ = os.Rename(temporary, source)\n+\t\t\treturn err\n+\t\t}\n+\t\treturn nil\n+\t}\n+\treturn os.Rename(source, destination)\n+}\n+\n+func rollbackMove(plan MovePlan) error {\n+\tvar failures []string\n+\tfor _, item := range plan.rewrites {\n+\t\tif _, err := os.Stat(item.rewrite.Path); err != nil {\n+\t\t\tif !os.IsNotExist(err) {\n+\t\t\t\tfailures = append(failures, fmt.Sprintf(\"stat %s: %v\", item.rewrite.Path, err))\n+\t\t\t}\n+\t\t\tcontinue\n+\t\t}\n+\t\tif err := replaceGenerated(item.rewrite.Path, item.rewrite.oldData, item.mode); err != nil {\n+\t\t\tfailures = append(failures, fmt.Sprintf(\"restore %s: %v\", item.rewrite.Path, err))\n+\t\t}\n+\t}\n+\tif err := renameMovePath(plan.Destination, plan.Source); err != nil {\n+\t\tfailures = append(failures, fmt.Sprintf(\"restore move: %v\", err))\n+\t}\n+\tif len(failures) > 0 {\n+\t\treturn errors.New(strings.Join(failures, \"; \"))\n+\t}\n+\treturn nil\n+}\n@@ -0,0 +1,131 @@\n+package links\n+\n+import (\n+\t\"fmt\"\n+\t\"os\"\n+\t\"path/filepath\"\n+\t\"strings\"\n+\n+\t\"github.com/Lokee86/demon-docs/internal/repository\"\n+)\n+\n+func validateMoveContainment(root, source, destination string) error {\n+\trealRoot, err := filepath.EvalSymlinks(root)\n+\tif err != nil {\n+\t\treturn fmt.Errorf(\"resolve repository root %s: %w\", root, err)\n+\t}\n+\trealSource, err := filepath.EvalSymlinks(source)\n+\tif err != nil {\n+\t\treturn fmt.Errorf(\"resolve move source %s: %w\", source, err)\n+\t}\n+\tif !repository.Contains(realRoot, realSource) {\n+\t\treturn fmt.Errorf(\"move source resolves outside repository root: %s\", source)\n+\t}\n+\trealDestinationParent, err := filepath.EvalSymlinks(filepath.Dir(destination))\n+\tif err != nil {\n+\t\treturn fmt.Errorf(\"resolve move destination parent %s: %w\", filepath.Dir(destination), err)\n+\t}\n+\tif !repository.Contains(realRoot, realDestinationParent) {\n+\t\treturn fmt.Errorf(\"move destination resolves outside repository root: %s\", destination)\n+\t}\n+\treturn nil\n+}\n+\n+func renderMoveTarget(inventory *inventory, syntax, originalPath string, style targetStyle, sourcePath, targetPath, movedSource, destination string) string {\n+\tif syntax != \"wiki\" || !isBareWikiPath(originalPath) || bareWikiUnambiguousAfterMove(inventory, originalPath, sourcePath, targetPath, movedSource, destination) {\n+\t\treturn renderTargetForSyntax(syntax, originalPath, style, sourcePath, targetPath)\n+\t}\n+\trendered := renderTargetPath(style, originalPath, sourcePath, targetPath)\n+\tif strings.EqualFold(filepath.Ext